    <script>
        class TrigVisualizer {
            constructor() {
                this.canvas = document.getElementById('unitCircleCanvas');
                this.ctx = this.canvas.getContext('2d');

                this.dom = {
                    slider: document.getElementById('angleSlider'),
                    playPauseBtn: document.getElementById('playPauseBtn'),
                    degOut: document.getElementById('angleDeg'),
                    radOut: document.getElementById('angleRad'),
                    sin: document.getElementById('val-sin'),
                    cos: document.getElementById('val-cos'),
                    tan: document.getElementById('val-tan'),
                    sec: document.getElementById('val-sec'),
                    csc: document.getElementById('val-csc'),
                    cot: document.getElementById('val-cot'),
                    p: document.getElementById('val-p'),
                    sinh: document.getElementById('val-sinh'),
                    cosh: document.getElementById('val-cosh'),
                    tanh: document.getElementById('val-tanh'),
                    sr: document.getElementById('sr-announcer')
                };

                this.colors = {
                    bg: getComputedStyle(document.documentElement).getPropertyValue('--surface-color').trim(),
                    grid: '#4a4a68',
                    circle: '#e0e0e5',
                    hyperbola: getComputedStyle(document.documentElement).getPropertyValue('--color-hyperbola').trim(),
                    cos: getComputedStyle(document.documentElement).getPropertyValue('--color-cos').trim(),
                    sin: getComputedStyle(document.documentElement).getPropertyValue('--color-sin').trim(),
                    tan: getComputedStyle(document.documentElement).getPropertyValue('--color-tan').trim(),
                    sec: getComputedStyle(document.documentElement).getPropertyValue('--color-sec').trim(),
                    csc: getComputedStyle(document.documentElement).getPropertyValue('--color-csc').trim(),
                    cot: getComputedStyle(document.documentElement).getPropertyValue('--color-cot').trim(),
                    connectionGlow: getComputedStyle(document.documentElement).getPropertyValue('--color-connection-glow').trim(),
                    text: getComputedStyle(document.documentElement).getPropertyValue('--primary-text-color').trim(),
                };

                this.state = {
                    angleRad: 0,
                    isPlaying: false,
                    animationFrameId: null,
                    connectionHighlight: 0, // 0 to 1 for fade effect
                };

                this.epsilon = 1e-9;
                this.maxVal = 10000; // For formatting large numbers
                this.scale = 1;
                this.originX = 0;
                this.originY = 0;
                this.canvasBounds = { x: 0, y: 0, width: 0, height: 0 };

                this.init();
            }

            init() {
                this.setupCanvas();
                this.attachEventListeners();
                this.setAngle(parseFloat(this.dom.slider.value));
            }

            attachEventListeners() {
                window.addEventListener('resize', () => this.setupCanvas());
                this.dom.slider.addEventListener('input', (e) => this.setAngle(parseFloat(e.target.value)));
                this.dom.playPauseBtn.addEventListener('click', () => this.togglePlay());

                let isDragging = false;
                this.canvas.addEventListener('mousedown', (e) => {
                    isDragging = true;
                    this.handleCanvasInteraction(e);
                });
                this.canvas.addEventListener('mousemove', (e) => {
                    if (isDragging) this.handleCanvasInteraction(e);
                });
                this.canvas.addEventListener('mouseup', () => isDragging = false);
                this.canvas.addEventListener('mouseleave', () => isDragging = false);
            }

            handleCanvasInteraction(e) {
                const rect = this.canvas.getBoundingClientRect();
                const x = e.clientX - rect.left - this.originX;
                const y = this.originY - (e.clientY - rect.top);
                let angle = Math.atan2(y, x);
                if (angle < 0) angle += 2 * Math.PI;
                this.setAngle(angle * 180 / Math.PI);
            }

            setupCanvas() {
                const dpr = window.devicePixelRatio || 1;
                const rect = this.canvas.parentElement.getBoundingClientRect();
                this.canvas.width = rect.width * dpr;
                this.canvas.height = rect.height * dpr;
                this.ctx.scale(dpr, dpr);

                const size = Math.min(rect.width, rect.height);
                this.scale = size / 5; // View from -2.5 to 2.5
                this.originX = rect.width / 2;
                this.originY = rect.height / 2;
                this.canvasBounds = { x: -this.originX / this.scale, y: -this.originY / this.scale, width: rect.width / this.scale, height: rect.height / this.scale };

                this.draw();
            }

            setAngle(deg) {
                this.dom.slider.value = deg;
                this.state.angleRad = deg * Math.PI / 180;
                this.state.connectionHighlight = 1.0; // Trigger highlight animation
                this.updateAndDraw();
                this.announceUpdate();
            }

            togglePlay() {
                this.state.isPlaying = !this.state.isPlaying;
                this.dom.playPauseBtn.classList.toggle('playing', this.state.isPlaying);
                this.dom.playPauseBtn.setAttribute('aria-label', this.state.isPlaying ? 'Pause animation' : 'Play animation');
                if (this.state.isPlaying) {
                    this.animate();
                } else {
                    cancelAnimationFrame(this.state.animationFrameId);
                }
            }

            animate() {
                const currentDeg = parseFloat(this.dom.slider.value);
                const newDeg = (currentDeg + 0.1) % 360;
                this.setAngle(newDeg);
                this.state.animationFrameId = requestAnimationFrame(() => this.animate());
            }

            updateAndDraw() {
                this.updateValues();
                requestAnimationFrame(() => this.draw());
            }

            updateValues() {
                const t = this.state.angleRad;
                const cos_t = Math.cos(t);
                const sin_t = Math.sin(t);

                this.values = {
                    cos_t, sin_t,
                    tan_t: Math.abs(cos_t) < this.epsilon ? Infinity * Math.sign(sin_t) : sin_t / cos_t,
                    sec_t: Math.abs(cos_t) < this.epsilon ? Infinity * Math.sign(cos_t) : 1 / cos_t,
                    csc_t: Math.abs(sin_t) < this.epsilon ? Infinity * Math.sign(sin_t) : 1 / sin_t,
                    cot_t: Math.abs(sin_t) < this.epsilon ? Infinity * Math.sign(cos_t) : cos_t / sin_t,
                };

                const p = Math.asinh(this.values.tan_t);
                this.values.p = p;
                this.values.cosh_p = Math.cosh(p);
                this.values.sinh_p = Math.sinh(p);
                this.values.tanh_p = Math.tanh(p);

                this.updateUI();
            }

            formatVal(val) {
                if (isNaN(val)) return 'undef';
                if (Math.abs(val) === Infinity) return '∞';
                if (Math.abs(val) > this.maxVal) return val.toExponential(2);
                return val.toFixed(3);
            }

            updateUI() {
                const deg = this.state.angleRad * 180 / Math.PI;
                this.dom.degOut.textContent = `${deg.toFixed(1)}°`;
                this.dom.radOut.textContent = `${this.state.angleRad.toFixed(3)} rad`;
                this.dom.slider.setAttribute('aria-valuenow', deg.toFixed(1));
                this.dom.slider.setAttribute('aria-valuetext', `${deg.toFixed(1)} degrees`);

                this.dom.sin.textContent = this.formatVal(this.values.sin_t);
                this.dom.cos.textContent = this.formatVal(this.values.cos_t);
                this.dom.tan.textContent = this.formatVal(this.values.tan_t);
                this.dom.sec.textContent = this.formatVal(this.values.sec_t);
                this.dom.csc.textContent = this.formatVal(this.values.csc_t);
                this.dom.cot.textContent = this.formatVal(this.values.cot_t);

                this.dom.p.textContent = this.formatVal(this.values.p);
                this.dom.sinh.textContent = this.formatVal(this.values.sinh_p);
                this.dom.cosh.textContent = this.formatVal(this.values.cosh_p);
                this.dom.tanh.textContent = this.formatVal(this.values.tanh_p);
            }

            draw() {
                const { ctx, originX, originY, scale, colors, values } = this;
                const { cos_t, sin_t } = values;
                const rect = this.canvas.getBoundingClientRect();
                ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
                ctx.fillStyle = colors.bg;
                ctx.fillRect(0, 0, rect.width, rect.height);

                // Grid and Axes
                this.drawLine(-2.5, 0, 2.5, 0, colors.grid, 1);
                this.drawLine(0, -2.5, 0, 2.5, colors.grid, 1);

                // Unit Circle
                ctx.beginPath();
                ctx.arc(originX, originY, scale, 0, 2 * Math.PI);
                ctx.strokeStyle = colors.circle;
                ctx.lineWidth = 1.5;
                ctx.stroke();

                // Unit Hyperbola
                ctx.beginPath();
                for (let y = -2.5; y <= 2.5; y += 0.01) {
                    let x = Math.sqrt(1 + y * y);
                    if (y === -2.5) ctx.moveTo(originX + x * scale, originY - y * scale);
                    else ctx.lineTo(originX + x * scale, originY - y * scale);
                }
                ctx.strokeStyle = colors.hyperbola;
                ctx.stroke();

                // Connection Highlight (sec(θ) = cosh(p))
                if (this.state.connectionHighlight > 0 && isFinite(values.cosh_p)) {
                    ctx.globalAlpha = this.state.connectionHighlight;
                    this.drawLine(0, 0, values.cosh_p, 0, this.colors.connectionGlow, 12);
                    ctx.globalAlpha = 1.0;
                    this.state.connectionHighlight -= 0.02;
                    requestAnimationFrame(() => this.draw());
                }

                // Circular Functions
                this.drawLine(0, 0, cos_t, sin_t, colors.circle, 2); // Radius
                this.drawLine(0, 0, cos_t, 0, colors.cos, 4); // cos
                this.drawLine(cos_t, 0, cos_t, sin_t, colors.sin, 4); // sin
                if (isFinite(values.tan_t)) this.drawLine(1, 0, 1, values.tan_t, colors.tan, 4); // tan
                if (isFinite(values.sec_t)) this.drawLine(0, 0, values.sec_t, 0, colors.sec, 4, [5, 5]); // sec

                // Hyperbolic Functions
                if (isFinite(values.cosh_p)) {
                    this.drawLine(0, 0, values.cosh_p, 0, colors.cos, 4); // cosh
                    this.drawLine(values.cosh_p, 0, values.cosh_p, values.sinh_p, colors.sin, 4); // sinh
                    this.drawLine(1, 0, 1, values.tanh_p, colors.tan, 4, [5, 5]); // tanh
                }

                // Points
                this.drawPoint(cos_t, sin_t, colors.circle, 6);
                if (isFinite(values.cosh_p)) {
                    this.drawPoint(values.cosh_p, values.sinh_p, colors.hyperbola, 6);
                }

                // Angle Arc
                ctx.beginPath();
                ctx.moveTo(originX, originY);
                ctx.arc(originX, originY, scale * 0.3, 0, -this.state.angleRad, true);
                ctx.closePath();
                ctx.fillStyle = 'rgba(0, 170, 255, 0.2)';
                ctx.fill();
                this.drawText('θ', 0.4 * Math.cos(this.state.angleRad / 2), 0.4 * Math.sin(this.state.angleRad / 2), colors.text);
            }

            drawLine(x1, y1, x2, y2, color, width = 2, dash = []) {
                this.ctx.beginPath();
                this.ctx.moveTo(this.originX + x1 * this.scale, this.originY - y1 * this.scale);
                this.ctx.lineTo(this.originX + x2 * this.scale, this.originY - y2 * this.scale);
                this.ctx.strokeStyle = color;
                this.ctx.lineWidth = width;
                this.ctx.setLineDash(dash);
                this.ctx.stroke();
                this.ctx.setLineDash([]);
            }

            drawPoint(x, y, color, radius = 5) {
                this.ctx.beginPath();
                this.ctx.arc(this.originX + x * this.scale, this.originY - y * this.scale, radius, 0, 2 * Math.PI);
                this.ctx.fillStyle = color;
                this.ctx.fill();
            }

            drawText(text, x, y, color, size = 14) {
                this.ctx.fillStyle = color;
                this.ctx.font = `${size}px ${getComputedStyle(document.documentElement).getPropertyValue('--font-family-sans')}`;
                this.ctx.textAlign = 'center';
                this.ctx.textBaseline = 'middle';
                this.ctx.fillText(text, this.originX + x * this.scale, this.originY - y * this.scale);
            }

            announceUpdate() {
                clearTimeout(this.debounceTimer);
                this.debounceTimer = setTimeout(() => {
