                this.dom.tan.textContent = this.formatVal(this.values.tan_t);
                this.dom.sec.textContent = this.formatVal(this.values.sec_t);
                this.dom.csc.textContent = this.formatVal(this.values.csc_t);
                this.dom.cot.textContent = this.formatVal(this.values.cot_t);

                this.dom.p.textContent = this.formatVal(this.values.p);
                this.dom.sinh.textContent = this.formatVal(this.values.sinh_p);
                this.dom.cosh.textContent = this.formatVal(this.values.cosh_p);
                this.dom.tanh.textContent = this.formatVal(this.values.tanh_p);
            }

            draw() {
                const { ctx, originX, originY, scale, colors, values } = this;
                const { cos_t, sin_t } = values;
                const rect = this.canvas.getBoundingClientRect();
                ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
                ctx.fillStyle = colors.bg;
                ctx.fillRect(0, 0, rect.width, rect.height);

                // Grid and Axes
                this.drawLine(-2.5, 0, 2.5, 0, colors.grid, 1);
                this.drawLine(0, -2.5, 0, 2.5, colors.grid, 1);

                // Unit Circle
                ctx.beginPath();
                ctx.arc(originX, originY, scale, 0, 2 * Math.PI);
                ctx.strokeStyle = colors.circle;
                ctx.lineWidth = 1.5;
                ctx.stroke();

                // Unit Hyperbola
                ctx.beginPath();
                for (let y = -2.5; y <= 2.5; y += 0.01) {
                    let x = Math.sqrt(1 + y * y);
                    if (y === -2.5) ctx.moveTo(originX + x * scale, originY - y * scale);
                    else ctx.lineTo(originX + x * scale, originY - y * scale);
                }
                ctx.strokeStyle = colors.hyperbola;
                ctx.stroke();

                // Connection Highlight (sec(θ) = cosh(p))
                if (this.state.connectionHighlight > 0 && isFinite(values.cosh_p)) {
                    ctx.globalAlpha = this.state.connectionHighlight;
                    this.drawLine(0, 0, values.cosh_p, 0, this.colors.connectionGlow, 12);
                    ctx.globalAlpha = 1.0;
                    this.state.connectionHighlight -= 0.02;
                    requestAnimationFrame(() => this.draw());
                }

                // Circular Functions
                this.drawLine(0, 0, cos_t, sin_t, colors.circle, 2); // Radius
                this.drawLine(0, 0, cos_t, 0, colors.cos, 4); // cos
                this.drawLine(cos_t, 0, cos_t, sin_t, colors.sin, 4); // sin
                if (isFinite(values.tan_t)) this.drawLine(1, 0, 1, values.tan_t, colors.tan, 4); // tan
                if (isFinite(values.sec_t)) this.drawLine(0, 0, values.sec_t, 0, colors.sec, 4, [5, 5]); // sec

                // Hyperbolic Functions
                if (isFinite(values.cosh_p)) {
                    this.drawLine(0, 0, values.cosh_p, 0, colors.cos, 4); // cosh
                    this.drawLine(values.cosh_p, 0, values.cosh_p, values.sinh_p, colors.sin, 4); // sinh
                    this.drawLine(1, 0, 1, values.tanh_p, colors.tan, 4, [5, 5]); // tanh
                }

                // Points
                this.drawPoint(cos_t, sin_t, colors.circle, 6);
                if (isFinite(values.cosh_p)) {
                    this.drawPoint(values.cosh_p, values.sinh_p, colors.hyperbola, 6);
                }

                // Angle Arc
                ctx.beginPath();
                ctx.moveTo(originX, originY);
                ctx.arc(originX, originY, scale * 0.3, 0, -this.state.angleRad, true);
                ctx.closePath();
                ctx.fillStyle = 'rgba(0, 170, 255, 0.2)';
                ctx.fill();
                this.drawText('θ', 0.4 * Math.cos(this.state.angleRad / 2), 0.4 * Math.sin(this.state.angleRad / 2), colors.text);
            }

            drawLine(x1, y1, x2, y2, color, width = 2, dash = []) {
                this.ctx.beginPath();
                this.ctx.moveTo(this.originX + x1 * this.scale, this.originY - y1 * this.scale);
                this.ctx.lineTo(this.originX + x2 * this.scale, this.originY - y2 * this.scale);
                this.ctx.strokeStyle = color;
                this.ctx.lineWidth = width;
                this.ctx.setLineDash(dash);
                this.ctx.stroke();
                this.ctx.setLineDash([]);
            }

            drawPoint(x, y, color, radius = 5) {
                this.ctx.beginPath();
                this.ctx.arc(this.originX + x * this.scale, this.originY - y * this.scale, radius, 0, 2 * Math.PI);
                this.ctx.fillStyle = color;
                this.ctx.fill();
            }

            drawText(text, x, y, color, size = 14) {
                this.ctx.fillStyle = color;
                this.ctx.font = `${size}px ${getComputedStyle(document.documentElement).getPropertyValue('--font-family-sans')}`;
                this.ctx.textAlign = 'center';
                this.ctx.textBaseline = 'middle';
                this.ctx.fillText(text, this.originX + x * this.scale, this.originY - y * this.scale);
            }

            announceUpdate() {
                clearTimeout(this.debounceTimer);
                this.debounceTimer = setTimeout(() => {
                    const deg = (this.state.angleRad * 180 / Math.PI).toFixed(1);
                    const sec = this.dom.sec.textContent;
                    const cosh = this.dom.cosh.textContent;
                    this.dom.sr.textContent = `Angle ${deg} degrees. Secant theta is ${sec}. Cosh p is ${cosh}.`;
                }, 500);
            }
        }

