            drawHyperbolicFunctions() {
                const { cosh_p, sinh_p, tanh_p } = this.values;
                this.drawLine(0, 0, cosh_p, sinh_p, this.colors.hyperbola, 2);

                this.drawLine(cosh_p, 0, cosh_p, sinh_p, this.colors.sin, 4, [3, 3]);
                this.drawLabel('sinh(p)', cosh_p, 0, cosh_p, sinh_p);

                this.drawLine(0, 0, cosh_p, 0, this.colors.cos, 4, [3, 3]);
                this.drawLabel('cosh(p)', 0, 0, cosh_p, 0);

                this.drawLine(1, 0, 1, tanh_p, this.colors.tan, 4, [3, 3]);
                this.drawLabel('tanh(p)', 1, 0, 1, tanh_p);
            }

            drawHyperbolicSector() {
                const { p } = this.values;
                if (Math.abs(p) < 0.01) return;

                this.ctx.beginPath();
                this.ctx.moveTo(this.originX, this.originY);
                this.ctx.lineTo(this.originX + 1 * this.scale, this.originY);

                const steps = 50;
                for (let i = 1; i <= steps; i++) {
                    const u = (i / steps) * p;
                    const x = Math.cosh(u);
                    const y = Math.sinh(u);
                    this.ctx.lineTo(this.originX + x * this.scale, this.originY - y * this.scale);
                }
                this.ctx.closePath();
                this.ctx.fillStyle = this.colors.hyperbolicArea;
                this.ctx.fill();

                const label_u = p / 2;
                const label_x = Math.cosh(label_u) * 0.8;
                const label_y = Math.sinh(label_u) * 0.8;
                this.drawText("p/2", label_x, label_y, this.colors.hyperbola, 14);
            }

            drawConnectionHighlight() {
                if (!this.state.isPulsing || this.state.isGudermannianAnimating) return;
                const { sec_t, cosh_p } = this.values;

                const pulse = (Math.sin(this.state.pulseTime) + 1) / 2;
                this.ctx.save();
                this.ctx.shadowBlur = pulse * 25;
                this.ctx.shadowColor = this.colors.connectionGlow;

                this.drawLine(0, 0, sec_t, 0, this.colors.sec, 5);
                this.drawLine(0, 0, cosh_p, 0, this.colors.sec, 5);

                this.ctx.restore();
            }

            drawGudermannianAnimation() {
                const { sec_t, sinh_p } = this.values;
                const progress = this.state.gudermannianProgress;
                const easeInOut = 0.5 - 0.5 * Math.cos(progress * Math.PI);

                this.ctx.save();
                this.ctx.shadowBlur = 25;
                this.ctx.shadowColor = this.colors.connectionGlow;

                // Phase 1: Highlight sec(θ)
                const secProgress = Math.min(1, progress * 2);
                const secEase = 0.5 - 0.5 * Math.cos(secProgress * Math.PI);
                this.drawPoint(sec_t * secEase, 0, this.colors.sec, 8);

                // Phase 2: Connect sec(θ) to cosh(p) point
                if (progress > 0.5) {
                    const connectProgress = (progress - 0.5) * 2;
                    const connectEase = 0.5 - 0.5 * Math.cos(connectProgress * Math.PI);
                    this.drawLine(sec_t, 0, sec_t, sinh_p, this.colors.connectionGlow, 3);
                    this.drawPoint(sec_t, sinh_p * connectEase, this.colors.sec, 8);
                }
                this.ctx.restore();

                // Draw formula text
                this.ctx.fillStyle = 'rgba(255, 255, 255, ' + (easeInOut * 2 * (1 - easeInOut)) + ')'; // Fade in and out
                this.ctx.font = `bold 20px ${this.colors.fontFamily}`;
                this.ctx.textAlign = 'center';
                this.ctx.textBaseline = 'bottom';
                this.ctx.fillText(`sec(θ) = cosh(p) = ${this.formatVal(sec_t)}`, this.originX, this.originY - 2.2 * this.scale);
            }

            drawPointsAndLabels() {
                const { cos_t, sin_t, cosh_p, sinh_p } = this.values;

                this.drawPoint(cos_t, sin_t, this.colors.circle, 6);
                if (this.state.isConnectionValid) {
                    this.drawPoint(cosh_p, sinh_p, this.colors.hyperbola, 6);
                }

                this.ctx.beginPath();
                this.ctx.moveTo(this.originX, this.originY);
                this.ctx.arc(this.originX, this.originY, this.scale * 0.3, 0, -this.state.angleRad, true);
                this.ctx.closePath();
                this.ctx.fillStyle = 'rgba(0, 170, 255, 0.2)';
                this.ctx.fill();
                this.drawText('θ', 0.4 * Math.cos(this.state.angleRad / 2), 0.4 * Math.sin(this.state.angleRad / 2), this.colors.text, 14);
            }

            // --- Drawing Utilities ---
            drawLine(x1, y1, x2, y2, color, width = 2, dash = []) {
                this.ctx.beginPath();
                this.ctx.moveTo(this.originX + x1 * this.scale, this.originY - y1 * this.scale);
                this.ctx.lineTo(this.originX + x2 * this.scale, this.originY - y2 * this.scale);
                this.ctx.strokeStyle = color;
                this.ctx.lineWidth = width;
                this.ctx.setLineDash(dash);
                this.ctx.stroke();
                this.ctx.setLineDash([]);
            }

            drawPoint(x, y, color, radius = 5) {
                this.ctx.beginPath();
                this.ctx.arc(this.originX + x * this.scale, this.originY - y * this.scale, radius, 0, 2 * Math.PI);
                this.ctx.fillStyle = color;
                this.ctx.fill();
            }

            drawText(text, x, y, color, size = 14) {
                this.ctx.fillStyle = color;
                this.ctx.font = `${size}px ${this.colors.fontFamily}`;
                this.ctx.textAlign = 'center';
                this.ctx.textBaseline = 'middle';
                this.ctx.fillText(text, this.originX + x * this.scale, this.originY - y * this.scale);
            }

            drawLabel(text, x1, y1, x2, y2) {
                const midX = (x1 + x2) / 2;
                const midY = (y1 + y2) / 2;
                const angle = Math.atan2(y2 - y1, x2 - x1);

                let offsetX = -Math.sin(angle) * 0.2;
                let offsetY = Math.cos(angle) * 0.2;

                // Prevent labels from being upside down
                if (Math.abs(angle) > Math.PI / 2) {
                    offsetX *= -1;
                    offsetY *= -1;
                }

                this.ctx.save();
                this.ctx.fillStyle = this.colors.text;
                this.ctx.font = `13px ${this.colors.fontFamily}`;
                this.ctx.textAlign = 'center';
                this.ctx.textBaseline = 'middle';
                this.ctx.fillText(text, this.originX + (midX + offsetX) * this.scale, this.originY - (midY + offsetY) * this.scale);
                this.ctx.restore();
            }

            announceUpdate() {
                clearTimeout(this.debounceTimer);
                this.debounceTimer = setTimeout(() => {
                    const deg = (this.state.angleRad * 180 / Math.PI).toFixed(1);
                    let announcement = `Angle ${deg} degrees.`;
                    if (this.state.isConnectionValid) {
                        const sec = this.dom.sec.textContent;
                        const cosh = this.dom.cosh.textContent;
                        announcement += ` Secant theta is ${sec}. Cosh p is ${cosh}.`;
                    } else {
                        announcement += ` Hyperbolic connection is not valid at this angle.`;
                    }
                    this.dom.sr.textContent = announcement;
                }, 500);
            }
        }

        document.addEventListener('DOMContentLoaded', () => {
            new TrigVisualizer();
        });
    </script>
