                if (visibility.sin) this.drawLine(cos_t, 0, cos_t, sin_t, this.colors.sin, highlightedFunc === 'sin' ? 6 : 4, [], highlightedFunc === 'sin');
                if (visibility.cos) this.drawLine(0, 0, cos_t, 0, this.colors.cos, highlightedFunc === 'cos' ? 6 : 4, [], highlightedFunc === 'cos');
                if (isFinite(tan_t) && visibility.tan) this.drawLine(1, 0, 1, tan_t, this.colors.tan, highlightedFunc === 'tan' ? 6 : 4, [], highlightedFunc === 'tan');
                if (isFinite(cot_t) && visibility.cot) this.drawLine(0, 1, cot_t, 1, this.colors.cot, highlightedFunc === 'cot' ? 6 : 4, [], highlightedFunc === 'cot');
                if (isFinite(sec_t) && visibility.sec) this.drawLine(0, 0, sec_t, 0, this.colors.sec, highlightedFunc === 'sec' ? 6 : 4, [5, 5], highlightedFunc === 'sec');
                if (isFinite(csc_t) && visibility.csc) this.drawLine(0, 0, 0, csc_t, this.colors.csc, highlightedFunc === 'csc' ? 6 : 4, [5, 5], highlightedFunc === 'csc');
