            border-radius: 12px;
            padding: 1.5rem;
            overflow-y: auto;
            display: flex;
            flex-direction: column;
            gap: 1.5rem;
        }

        .control-section h2, .values-section h2, .display-section h2 {
            font-size: 1.25rem;
            margin-bottom: 1rem;
            border-bottom: 1px solid var(--secondary-text-color);
            padding-bottom: 0.5rem;
            color: var(--accent-color);
        }

        .slider-group {
            display: flex;
            flex-direction: column;
            gap: 0.5rem;
        }

        .slider-group label {
            font-weight: 500;
            color: var(--secondary-text-color);
        }

        .slider-output {
            display: flex;
            justify-content: space-between;
            font-family: var(--font-family-mono);
            font-size: 1.1rem;
        }

        input[type="range"] {
            -webkit-appearance: none;
            appearance: none;
            width: 100%;
            height: 8px;
            background: var(--bg-color);
            border-radius: 5px;
            outline: none;
            cursor: pointer;
            transition: opacity 0.2s ease;
        }
        input[type="range"]:disabled {
            cursor: not-allowed;
            opacity: 0.5;
        }

        input[type="range"]::-webkit-slider-thumb {
            -webkit-appearance: none;
            appearance: none;
            width: 20px;
            height: 20px;
            background: var(--accent-color);
            border-radius: 50%;
            border: 2px solid var(--bg-color);
            transition: box-shadow 0.2s ease-in-out, background-color 0.2s ease;
        }
        input[type="range"]:disabled::-webkit-slider-thumb {
            background-color: var(--secondary-text-color);
        }

        input[type="range"]::-moz-range-thumb {
            width: 20px;
            height: 20px;
            background: var(--accent-color);
            border-radius: 50%;
            border: 2px solid var(--bg-color);
            transition: box-shadow 0.2s ease-in-out, background-color 0.2s ease;
        }
        input[type="range"]:disabled::-moz-range-thumb {
            background-color: var(--secondary-text-color);
        }

        input[type="range"]:focus-visible::-webkit-slider-thumb {
            box-shadow: 0 0 0 3px var(--bg-color), 0 0 0 5px var(--accent-glow);
        }
        input[type="range"]:focus-visible::-moz-range-thumb {
            box-shadow: 0 0 0 3px var(--bg-color), 0 0 0 5px var(--accent-glow);
        }

        .animation-controls {
            display: flex;
            gap: 1rem;
            align-items: center;
        }

        .play-pause-btn {
            background-color: var(--accent-color);
            color: var(--bg-color);
            border: none;
            border-radius: 50%;
            width: 44px;
            height: 44px;
            cursor: pointer;
            display: flex;
            justify-content: center;
            align-items: center;
            transition: background-color 0.2s ease, transform 0.2s ease, opacity 0.3s ease;
            flex-shrink: 0;
        }
        .play-pause-btn:hover:not(:disabled) {
            transform: scale(1.05);
            filter: brightness(1.1);
        }
        .play-pause-btn:focus-visible {
            outline: 2px solid var(--accent-color);
            outline-offset: 2px;
        }
        .play-pause-btn svg {
            width: 24px;
            height: 24px;
            fill: var(--bg-color);
        }
        .play-pause-btn .icon-pause { display: none; }
        .play-pause-btn.playing .icon-pause { display: block; }
        .play-pause-btn.playing .icon-play { display: none; }

        .play-pause-btn:disabled {
            background-color: var(--secondary-text-color);
            cursor: not-allowed;
            opacity: 0.5;
        }

        .values-grid {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(130px, 1fr));
            gap: 1rem;
        }

        .value-card {
            display: flex;
            flex-direction: column;
            border-left: 3px solid var(--card-color, var(--secondary-text-color));
            padding: 0.25rem 0.75rem;
            border-radius: 0 4px 4px 0;
            transition: border-color 0.3s ease, background-color 0.3s ease;
        }

        .value-card.is-highlighted {
            background-color: rgba(255, 255, 255, 0.05);
            border-left-width: 5px;
        }

        .value-card dt {
            font-size: 0.9rem;
            color: var(--secondary-text-color);
            font-family: var(--font-family-mono);
        }

        .value-card dd {
            font-size: 1.1rem;
            font-weight: 600;
            font-family: var(--font-family-mono);
            color: var(--card-color, var(--primary-text-color));
            transition: color 0.3s ease;
        }

        .connection-highlight {
            background-color: rgba(244, 67, 54, 0.1);
            --card-color: var(--color-sec) !important;
        }

        .values-section[aria-disabled="true"] {
            opacity: 0.5;
            transition: opacity 0.3s ease;
        }
        .values-section[aria-disabled="true"] .value-card {
            --card-color: var(--secondary-text-color);
        }
        .values-section[aria-disabled="true"] .value-card dd {
            color: var(--secondary-text-color);
        }

        .toggle-grid {
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            gap: 0.75rem;
        }

        .toggle-switch {
            display: flex;
            align-items: center;
            gap: 0.5rem;
            cursor: pointer;
            font-size: 0.9rem;
            user-select: none;
        }
        .toggle-switch input {
            position: absolute;
            opacity: 0;
            width: 0;
            height: 0;
        }
        .toggle-slider {
            position: relative;
            width: 34px;
            height: 20px;
            background-color: var(--bg-color);
            border-radius: 10px;
            transition: background-color 0.2s;
            border: 1px solid var(--secondary-text-color);
        }
        .toggle-slider::before {
            content: '';
            position: absolute;
            height: 14px;
            width: 14px;
            left: 2px;
            bottom: 2px;
            background-color: var(--secondary-text-color);
            border-radius: 50%;
            transition: transform 0.2s, background-color 0.2s;
        }
        .toggle-switch input:checked + .toggle-slider {
            background-color: var(--toggle-color, var(--accent-color));
            border-color: var(--toggle-color, var(--accent-color));
        }
        .toggle-switch input:checked + .toggle-slider::before {
            transform: translateX(14px);
            background-color: var(--bg-color);
        }
        .toggle-switch input:focus-visible + .toggle-slider {
            box-shadow: 0 0 0 2px var(--bg-color), 0 0 0 4px var(--accent-glow);
        }
        .toggle-switch span {
            font-family: var(--font-family-mono);
            color: var(--toggle-color, var(--primary-text-color));
        }

        footer {
            text-align: center;
            padding: 1.5rem 1rem;
            font-size: 0.9rem;
            color: var(--secondary-text-color);
            border-top: 1px solid var(--surface-color);
        }

        /* Responsive Layout */
        @media (max-width: 1200px) {
            main {
                grid-template-columns: 1fr;
                padding: 1rem;
            }
            .visualization-container {
                min-height: 60vw;
                max-height: 80vh;
            }
        }

        @media (max-width: 600px) {
            html {
                font-size: 14px;
            }
            header, footer {
                padding: 1rem;
            }
            main {
                padding: 0.5rem;
                gap: 1rem;
            }
            .controls-panel {
                padding: 1rem;
            }
            .values-grid {
                grid-template-columns: repeat(2, 1fr);
            }
            .toggle-grid {
                grid-template-columns: repeat(2, 1fr);
            }
        }
    </style>
</head>
<body>

    <header>
        <h1>Interactive Unit Circle & <span>Hyperbola Explorer</span></h1>
    </header>

    <main>
        <figure class="visualization-container" role="figure" aria-labelledby="canvas-title" aria-describedby="canvas-description">
            <h2 id="canvas-title" class="visually-hidden">Trigonometric Visualization</h2>
            <canvas id="mainCanvas" width="800" height="800" tabindex="0" aria-describedby="canvas-description"></canvas>
            <figcaption id="canvas-description" class="visually-hidden">
                Interactive canvas displaying the unit circle and unit hyperbola. Control the angle theta (θ) by dragging on the canvas, using the slider, or using arrow keys. Lines representing trigonometric functions can be toggled. When secant(θ) is valid, corresponding hyperbolic lines are drawn, highlighting the Gudermannian connection where sec(θ) = cosh(p).
            </figcaption>
        </figure>

        <aside class="controls-panel" aria-labelledby="controls-panel-heading">
            <h2 id="controls-panel-heading" class="visually-hidden">Controls and Values Panel</h2>
            <section class="control-section" aria-labelledby="controls-heading">
                <h2 id="controls-heading">Controls</h2>
                <div class="slider-group">
                    <label for="angleSlider">Angle (θ)</label>
                    <div class="animation-controls">
                        <button class="play-pause-btn" id="playPauseBtn" aria-label="Play animation">
                            <svg class="icon-play" viewBox="0 0 24 24" aria-hidden="true" focusable="false"><path d="M8 5v14l11-7z"></path></svg>
                            <svg class="icon-pause" viewBox="0 0 24 24" aria-hidden="true" focusable="false"><path d="M6 19h4V5H6v14zm8-14v14h4V5h-4z"></path></svg>
                        </button>
                        <input type="range" id="angleSlider" min="0" max="360" value="45" step="0.1" aria-valuemin="0" aria-valuemax="360" aria-valuenow="45" aria-valuetext="45.0 degrees">
                    </div>
                    <div class="slider-output">
                        <output id="angleDeg" for="angleSlider">45.0°</output>
                        <output id="angleRad" for="angleSlider">0.785 rad</output>
                    </div>
                </div>
                <div class="slider-group">
                    <label for="speedSlider">Animation Speed</label>
                    <input type="range" id="speedSlider" min="0.1" max="2" value="0.5" step="0.1" aria-label="Animation Speed">
                    <div class="slider-output">
                        <output id="speedOutput" for="speedSlider">0.5x</output>
                    </div>
                </div>
                <div class="slider-group">
                    <label for="gudermannianSlider">Gudermannian Connection: sec(θ) = cosh(p)</label>
                    <div class="animation-controls">
                        <button class="play-pause-btn" id="gudermannianPlayBtn" aria-label="Play Gudermannian animation">
                            <svg class="icon-play" viewBox="0 0 24 24" aria-hidden="true" focusable="false"><path d="M8 5v14l11-7z"></path></svg>
                            <svg class="icon-pause" viewBox="0 0 24 24" aria-hidden="true" focusable="false"><path d="M6 19h4V5H6v14zm8-14v14h4V5h-4z"></path></svg>
                        </button>
                        <input type="range" id="gudermannianSlider" min="0" max="1" value="0" step="0.001" aria-label="Gudermannian animation progress">
                    </div>
                </div>
            </section>

            <section class="display-section" aria-labelledby="display-heading">
                <h2 id="display-heading">Display Options</h2>
                <fieldset>
                    <legend class="visually-hidden">Toggle visibility of trigonometric functions</legend>
                    <div id="visibilityToggles" class="toggle-grid"></div>
                </fieldset>
            </section>

            <section class="values-section" aria-labelledby="circular-heading">
                <h2 id="circular-heading">Circular Functions</h2>
                <dl class="values-grid">
                    <div class="value-card" data-function="sin" style="--card-color: var(--color-sin);"><dt>sin(θ)</dt><dd id="val-sin">0.707</dd></div>
                    <div class="value-card" data-function="cos" style="--card-color: var(--color-cos);"><dt>cos(θ)</dt><dd id="val-cos">0.707</dd></div>
                    <div class="value-card" data-function="tan" style="--card-color: var(--color-tan);"><dt>tan(θ)</dt><dd id="val-tan">1.000</dd></div>
                    <div id="sec-card" class="value-card" data-function="sec" style="--card-color: var(--color-sec);"><dt>sec(θ)</dt><dd id="val-sec">1.414</dd></div>
                    <div class="value-card" data-function="csc" style="--card-color: var(--color-csc);"><dt>csc(θ)</dt><dd id="val-csc">1.414</dd></div>
                    <div class="value-card" data-function="cot" style="--card-color: var(--color-cot);"><dt>cot(θ)</dt><dd id="val-cot">1.000</dd></div>
                </dl>
            </section>

            <section id="hyperbolic-section" class="values-section" aria-labelledby="hyperbolic-heading">
                <h2 id="hyperbolic-heading">Hyperbolic Functions</h2>
                <p class="visually-hidden">Parameter p is calculated as p = ln(sec(θ) + tan(θ)). Hyperbolic values are shown only when sec(θ) ≥ 1.</p>
                <dl class="values-grid">
                    <div class="value-card" data-function="p" style="--card-color: var(--color-hyperbola);"><dt>p (area/2)</dt><dd id="val-p">0.881</dd></div>
                    <div class="value-card" data-function="sinh" style="--card-color: var(--color-sin);"><dt>sinh(p)</dt><dd id="val-sinh">1.000</dd></div>
                    <div id="cosh-card" class="value-card" data-function="cosh" style="--card-color: var(--color-cos);"><dt>cosh(p)</dt><dd id="val-cosh">1.414</dd></div>
                    <div class="value-card" data-function="tanh" style="--card-color: var(--color-tan);"><dt>tanh(p)</dt><dd id="val-tanh">0.707</dd></div>
                </dl>
            </section>
            <div id="sr-announcer" class="visually-hidden" aria-live="polite" aria-atomic="true"></div>
        </aside>
    </main>

    <footer>
        <p>Interactive Trigonometry Visualization &copy; 2024. All rights reserved.</p>
    </footer>

    <script>
        class TrigVisualizer {
            constructor() {
                this.canvas = document.getElementById('mainCanvas');
                if (!this.canvas) {
                    console.error("FATAL: Canvas element not found!");
                    return;
                }
                this.ctx = this.canvas.getContext('2d');

                this.dom = {
                    slider: document.getElementById('angleSlider'),
                    speedSlider: document.getElementById('speedSlider'),
                    playPauseBtn: document.getElementById('playPauseBtn'),
                    gudermannianSlider: document.getElementById('gudermannianSlider'),
                    gudermannianPlayBtn: document.getElementById('gudermannianPlayBtn'),
                    degOut: document.getElementById('angleDeg'),
                    radOut: document.getElementById('angleRad'),
                    speedOut: document.getElementById('speedOutput'),
                    sr: document.getElementById('sr-announcer'),
                    hyperbolicSection: document.getElementById('hyperbolic-section'),
                    secCard: document.getElementById('sec-card'),
                    coshCard: document.getElementById('cosh-card'),
                    visibilityToggles: document.getElementById('visibilityToggles'),
                    valueCards: document.querySelectorAll('.value-card'),
                };

                this.colors = this.getColors();
                this.functionDefs = this.getFunctionDefinitions();

                this.state = {
                    angleRad: 0,
                    isPlaying: false,
                    isPulsing: false,
                    isConnectionValid: false,
                    isGudermannianPlaying: false,
                    gudermannianProgress: 0,
                    highlightedFunc: null,
                    isDirty: true,
                    visibility: Object.fromEntries(this.functionDefs.map(f => [f.id, true])),
                };

                this.constants = {
                    epsilon: 1e-9,
                    maxVal: 10000,
                    gudermannianAnimSpeed: 0.5, // seconds for full animation
                    highlightThreshold: 10, // pixels for canvas hover
                };

                this.scale = 1;
                this.originX = 0;
                this.originY = 0;
                this.animationFrameId = null;
                this.lastFrameTime = performance.now();
                this.pulseTime = 0;

                this.init();
            }

            getColors() {
                const style = getComputedStyle(document.documentElement);
                return Object.fromEntries(
                    ['bg', 'grid', 'gridLabel', 'circle', 'hyperbola', 'cos', 'sin', 'tan', 'sec', 'csc', 'cot', 'connectionGlow', 'hyperbolicArea', 'text', 'fontFamily']
                    .map(name => [name, style.getPropertyValue(`--color-${name.toLowerCase()}`, style.getPropertyValue(`--${name}`)).trim()])
                );
            }

            getFunctionDefinitions() {
                return [
                    { id: 'sin', color: this.colors.sin }, { id: 'cos', color: this.colors.cos },
                    { id: 'tan', color: this.colors.tan }, { id: 'sec', color: this.colors.sec },
                    { id: 'csc', color: this.colors.csc }, { id: 'cot', color: this.colors.cot },
                    { id: 'p', color: this.colors.hyperbola }, { id: 'sinh', color: this.colors.sin },
                    { id: 'cosh', color: this.colors.cos }, { id: 'tanh', color: this.colors.tan }
                ];
            }

            init() {
                this.setupCanvas();
                this.createVisibilityToggles();
                this.attachEventListeners();
                this.setAngle(parseFloat(this.dom.slider.value));
                this.updateSpeed();
                this.animationLoop();
            }

            createVisibilityToggles() {
                const fragment = document.createDocumentFragment();
                this.functionDefs.forEach(({ id, color }) => {
                    const label = document.createElement('label');
                    label.className = 'toggle-switch';
                    label.style.setProperty('--toggle-color', color);

                    const input = document.createElement('input');
                    input.type = 'checkbox';
                    input.id = `toggle-${id}`;
                    input.dataset.function = id;
                    input.checked = this.state.visibility[id];

                    const slider = document.createElement('div');
                    slider.className = 'toggle-slider';

                    const text = document.createElement('span');
                    text.textContent = id;

                    label.append(input, slider, text);
                    fragment.appendChild(label);
                });
                this.dom.visibilityToggles.appendChild(fragment);
            }

            attachEventListeners() {
                window.addEventListener('resize', () => this.setupCanvas());
                this.dom.slider.addEventListener('input', (e) => this.setAngle(parseFloat(e.target.value)));
                this.dom.speedSlider.addEventListener('input', () => this.updateSpeed());
                this.dom.playPauseBtn.addEventListener('click', () => this.togglePlay());

                this.dom.gudermannianSlider.addEventListener('input', (e) => this.setGudermannianProgress(parseFloat(e.target.value)));
                this.dom.gudermannianPlayBtn.addEventListener('click', () => this.toggleGudermannianPlay());

                this.dom.visibilityToggles.addEventListener('change', (e) => {
                    if (e.target.type === 'checkbox') {
                        this.state.visibility[e.target.dataset.function] = e.target.checked;
                        this.requestDraw();
                    }
                });

                this.dom.valueCards.forEach(card => {
                    card.addEventListener('mouseenter', () => this.setHighlight(card.dataset.function));
                    card.addEventListener('mouseleave', () => this.setHighlight(null));
                });

                let isDragging = false;
                const handleInteraction = (e) => {
                    if (this.isAnyAnimationActive()) return;
                    e.preventDefault();
                    const touch = e.touches ? e.touches[0] : e;
                    const rect = this.canvas.getBoundingClientRect();
                    const x = (touch.clientX - rect.left) - this.originX;
                    const y = this.originY - (touch.clientY - rect.top);
                    let angle = Math.atan2(y, x);
                    if (angle < 0) angle += 2 * Math.PI;
                    this.setAngle(angle * 180 / Math.PI);
                };

                this.canvas.addEventListener('mousedown', (e) => { isDragging = true; handleInteraction(e); });
                this.canvas.addEventListener('mousemove', (e) => { 
                    if (isDragging) {
                        handleInteraction(e);
                    } else {
                        this.handleCanvasHover(e);
                    }
                });
                document.addEventListener('mouseup', () => { isDragging = false; });
                this.canvas.addEventListener('mouseleave', () => { 
                    isDragging = false;
                    this.setHighlight(null);
                });

                this.canvas.addEventListener('touchstart', (e) => { isDragging = true; handleInteraction(e); }, { passive: false });
                this.canvas.addEventListener('touchmove', (e) => { if (isDragging) handleInteraction(e); }, { passive: false });
                this.canvas.addEventListener('touchend', () => { isDragging = false; });
                this.canvas.addEventListener('touchcancel', () => { isDragging = false; });

                this.canvas.addEventListener('keydown', (e) => this.handleKeyDown(e));
            }

            handleKeyDown(e) {
                if (this.isAnyAnimationActive()) return;
                let change = 0;
                if (e.key === 'ArrowRight') change = e.shiftKey ? 5 : 1;
                if (e.key === 'ArrowLeft') change = e.shiftKey ? -5 : -1;

                if (change !== 0) {
                    e.preventDefault();
                    const currentDeg = parseFloat(this.dom.slider.value);
                    let newDeg = (currentDeg + change) % 360;
                    if (newDeg < 0) newDeg += 360;
                    this.setAngle(newDeg);
                }
            }

            setupCanvas() {
                const dpr = window.devicePixelRatio || 1;
                const rect = this.canvas.parentElement.getBoundingClientRect();
                this.canvas.width = rect.width * dpr;
                this.canvas.height = rect.height * dpr;
                this.ctx.scale(dpr, dpr);

                const size = Math.min(rect.width, rect.height);
                this.scale = size / 5.5;
                this.originX = rect.width / 2;
                this.originY = rect.height / 2;
                this.requestDraw();
            }

            setAngle(deg) {
                if (this.isAnyAnimationActive()) return;
                this.dom.slider.value = deg;
                this.state.angleRad = deg * Math.PI / 180;
                this.state.isPulsing = true;
                this.pulseTime = 0;
                this.updateValues();
                this.announceUpdate();
            }

            updateSpeed() {
                this.dom.speedOut.textContent = `${parseFloat(this.dom.speedSlider.value).toFixed(1)}x`;
            }

            togglePlay() {
                if (this.isAnyAnimationActive() && !this.state.isPlaying) return;
                this.state.isPlaying = !this.state.isPlaying;
                if (this.state.isPlaying) {
                    this.state.isGudermannianPlaying = false;
                }
                this.updateControlStates();
            }

            toggleGudermannianPlay() {
                if (!this.state.isConnectionValid) return;
                if (this.isAnyAnimationActive() && !this.state.isGudermannianPlaying) return;
                this.state.isGudermannianPlaying = !this.state.isGudermannianPlaying;
                if (this.state.isGudermannianPlaying) {
                    this.state.isPlaying = false;
                    if (this.state.gudermannianProgress >= 1) {
                        this.setGudermannianProgress(0);
                    }
                }
                this.updateControlStates();
            }

            setGudermannianProgress(progress) {
                this.state.gudermannianProgress = Math.max(0, Math.min(1, progress));
                this.dom.gudermannianSlider.value = this.state.gudermannianProgress;
                this.requestDraw();
            }

            isAnyAnimationActive() {
                return this.state.isPlaying || this.state.isGudermannianPlaying;
            }

            animationLoop(now) {
                const delta = (now - this.lastFrameTime) / 1000;
                this.lastFrameTime = now;
                let needsDraw = false;

                if (this.state.isPlaying) {
                    const currentDeg = parseFloat(this.dom.slider.value);
                    const speed = parseFloat(this.dom.speedSlider.value);
                    const newDeg = (currentDeg + speed * 30 * delta) % 360;
                    this.setAngle(newDeg);
                    needsDraw = true;
                }
                if (this.state.isGudermannianPlaying) {
                    let newProgress = this.state.gudermannianProgress + delta / this.constants.gudermannianAnimSpeed;
                    if (newProgress >= 1) {
                        newProgress = 1;
                        this.state.isGudermannianPlaying = false;
                        this.updateControlStates();
                    }
                    this.setGudermannianProgress(newProgress);
                    needsDraw = true;
                }
                if (this.state.isPulsing) {
                    this.pulseTime += delta * 4;
                    if (this.pulseTime > Math.PI) {
                        this.state.isPulsing = false;
                        this.pulseTime = 0;
                    }
                    needsDraw = true;
                }

                if (needsDraw || this.state.isDirty) {
                    this.draw();
                    this.state.isDirty = false;
                }
                this.animationFrameId = requestAnimationFrame((t) => this.animationLoop(t));
            }

            requestDraw() { this.state.isDirty = true; }

            updateValues() {
                const t = this.state.angleRad;
                const cos_t = Math.cos(t);
                const sin_t = Math.sin(t);

                this.values = {
                    cos_t, sin_t,
                    tan_t: Math.abs(cos_t) < this.constants.epsilon ? Infinity * Math.sign(sin_t) : sin_t / cos_t,
                    sec_t: Math.abs(cos_t) < this.constants.epsilon ? Infinity * Math.sign(cos_t) : 1 / cos_t,
                    csc_t: Math.abs(sin_t) < this.constants.epsilon ? Infinity * Math.sign(sin_t) : 1 / sin_t,
