            cursor: crosshair;
            touch-action: none;
        }
        #mainCanvas:focus-visible {
            outline: 3px solid var(--accent-color);
            outline-offset: -3px;
        }

        .controls-panel {
            background-color: var(--surface-color);
            border-radius: 12px;
            padding: 1.5rem;
            overflow-y: auto;
            display: flex;
            flex-direction: column;
            gap: 1.5rem;
        }

        .control-section h2, .values-section h2 {
            font-size: 1.25rem;
            margin-bottom: 1rem;
            border-bottom: 1px solid var(--secondary-text-color);
            padding-bottom: 0.5rem;
            color: var(--accent-color);
        }

        .slider-group, .animation-group {
            display: flex;
            flex-direction: column;
            gap: 0.5rem;
        }

        .slider-group label, .animation-group label {
            font-weight: 500;
            color: var(--secondary-text-color);
        }

        .slider-output {
            display: flex;
            justify-content: space-between;
            font-family: var(--font-family-mono);
            font-size: 1.1rem;
        }

        input[type="range"] {
            -webkit-appearance: none;
            appearance: none;
            width: 100%;
            height: 8px;
            background: var(--bg-color);
            border-radius: 5px;
            outline: none;
            cursor: pointer;
            transition: opacity 0.2s ease;
        }
        input[type="range"]:disabled {
            cursor: not-allowed;
            opacity: 0.5;
        }

        input[type="range"]::-webkit-slider-thumb {
            -webkit-appearance: none;
            appearance: none;
            width: 20px;
            height: 20px;
            background: var(--accent-color);
            border-radius: 50%;
            border: 2px solid var(--bg-color);
            transition: box-shadow 0.2s ease-in-out, background-color 0.2s ease;
        }
        input[type="range"]:disabled::-webkit-slider-thumb {
            background-color: var(--secondary-text-color);
        }

        input[type="range"]::-moz-range-thumb {
            width: 20px;
            height: 20px;
            background: var(--accent-color);
            border-radius: 50%;
            border: 2px solid var(--bg-color);
            transition: box-shadow 0.2s ease-in-out, background-color 0.2s ease;
        }
        input[type="range"]:disabled::-moz-range-thumb {
            background-color: var(--secondary-text-color);
        }

        input[type="range"]:focus-visible::-webkit-slider-thumb {
            box-shadow: 0 0 0 3px var(--bg-color), 0 0 0 5px var(--accent-glow);
        }
        input[type="range"]:focus-visible::-moz-range-thumb {
            box-shadow: 0 0 0 3px var(--bg-color), 0 0 0 5px var(--accent-glow);
        }

        .animation-controls {
            display: flex;
            gap: 1rem;
            align-items: center;
        }

        .play-pause-btn, .gudermannian-btn {
            background-color: var(--accent-color);
            color: var(--bg-color);
            border: none;
            border-radius: 50%;
            width: 44px;
            height: 44px;
            cursor: pointer;
            display: flex;
            justify-content: center;
            align-items: center;
            transition: background-color 0.2s ease, transform 0.2s ease, opacity 0.3s ease;
            flex-shrink: 0;
        }
        .play-pause-btn:hover:not(:disabled), .gudermannian-btn:hover:not(:disabled) {
            transform: scale(1.05);
        }
        .play-pause-btn:focus-visible, .gudermannian-btn:focus-visible {
            outline: 2px solid var(--accent-color);
            outline-offset: 2px;
        }
        .play-pause-btn svg, .gudermannian-btn svg {
            width: 24px;
            height: 24px;
            fill: var(--bg-color);
        }
        .play-pause-btn .icon-pause { display: none; }
        .play-pause-btn.playing .icon-pause { display: block; }
        .play-pause-btn.playing .icon-play { display: none; }

        .gudermannian-btn {
            background-color: var(--color-connection);
        }
        .gudermannian-btn:hover:not(:disabled) {
            background-color: #ff7961;
        }
        .gudermannian-btn:focus-visible {
            outline-color: var(--color-connection-glow);
        }

        .play-pause-btn:disabled, .gudermannian-btn:disabled {
            background-color: var(--secondary-text-color);
            cursor: not-allowed;
            opacity: 0.5;
        }

        .animation-group p {
            font-size: 0.9rem;
            color: var(--secondary-text-color);
            margin-top: -0.25rem;
        }

        .values-grid {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(130px, 1fr));
            gap: 1rem;
        }

        .value-card {
            display: flex;
            flex-direction: column;
            border-left: 3px solid var(--card-color, var(--secondary-text-color));
            padding-left: 0.75rem;
            transition: border-color 0.3s ease, background-color 0.3s ease;
        }

        .value-card dt {
            font-size: 0.9rem;
            color: var(--secondary-text-color);
            font-family: var(--font-family-mono);
        }

        .value-card dd {
            font-size: 1.1rem;
            font-weight: 600;
            font-family: var(--font-family-mono);
            color: var(--card-color, var(--primary-text-color));
            transition: color 0.3s ease;
        }

        .connection-highlight {
            background-color: rgba(244, 67, 54, 0.1);
            --card-color: var(--color-sec) !important;
        }

        .values-section[aria-disabled="true"] {
            opacity: 0.5;
            transition: opacity 0.3s ease;
        }
        .values-section[aria-disabled="true"] .value-card {
            --card-color: var(--secondary-text-color);
        }
        .values-section[aria-disabled="true"] .value-card dd {
            color: var(--secondary-text-color);
        }

        footer {
            text-align: center;
            padding: 1.5rem 1rem;
            font-size: 0.9rem;
            color: var(--secondary-text-color);
            border-top: 1px solid var(--surface-color);
        }

        /* Responsive Layout */
        @media (max-width: 1200px) {
            main {
                grid-template-columns: 1fr;
                padding: 1rem;
            }
            .visualization-container {
                min-height: 60vw;
                max-height: 80vh;
            }
        }

        @media (max-width: 600px) {
            html {
                font-size: 14px;
            }
            header, footer {
                padding: 1rem;
            }
            main {
                padding: 0.5rem;
                gap: 1rem;
            }
            .controls-panel {
                padding: 1rem;
            }
            .values-grid {
                grid-template-columns: repeat(2, 1fr);
            }
        }
    </style>
</head>
<body>

    <header>
        <h1>Interactive Unit Circle & <span>Hyperbola Explorer</span></h1>
    </header>

    <main>
        <figure class="visualization-container" role="figure" aria-labelledby="canvas-title" aria-describedby="canvas-description">
            <h2 id="canvas-title" class="visually-hidden">Trigonometric Visualization</h2>
            <canvas id="mainCanvas" width="800" height="800" tabindex="0" aria-describedby="canvas-description"></canvas>
            <figcaption id="canvas-description" class="visually-hidden">
                Interactive canvas displaying the unit circle and unit hyperbola. Control the angle theta (θ) by dragging the mouse/finger on the canvas, using the slider, or using the left and right arrow keys when the canvas is focused. Lines representing sine, cosine, tangent, secant, cosecant, and cotangent are drawn. When secant(θ) is greater than or equal to one, corresponding lines for sinh, cosh, and tanh are drawn for a parameter p, highlighting the Gudermannian connection where sec(θ) = cosh(p).
            </figcaption>
        </figure>

        <aside class="controls-panel">
            <section class="control-section" aria-labelledby="controls-heading">
                <h2 id="controls-heading">Controls</h2>
                <div class="slider-group">
                    <label for="angleSlider">Angle (θ)</label>
                    <div class="animation-controls">
                        <button class="play-pause-btn" id="playPauseBtn" aria-label="Play animation">
                            <svg class="icon-play" viewBox="0 0 24 24" aria-hidden="true" focusable="false"><path d="M8 5v14l11-7z"></path></svg>
                            <svg class="icon-pause" viewBox="0 0 24 24" aria-hidden="true" focusable="false"><path d="M6 19h4V5H6v14zm8-14v14h4V5h-4z"></path></svg>
                        </button>
                        <input type="range" id="angleSlider" min="0" max="360" value="45" step="0.1" aria-valuemin="0" aria-valuemax="360" aria-valuenow="45" aria-valuetext="45.0 degrees">
                    </div>
                    <div class="slider-output">
                        <output id="angleDeg" for="angleSlider">45.0°</output>
                        <output id="angleRad" for="angleSlider">0.785 rad</output>
                    </div>
                </div>
                <div class="slider-group">
                    <label for="speedSlider">Animation Speed</label>
                    <input type="range" id="speedSlider" min="0.1" max="2" value="0.5" step="0.1" aria-label="Animation Speed">
                    <div class="slider-output">
                        <output id="speedOutput" for="speedSlider">0.5x</output>
                    </div>
                </div>
                <div class="animation-group">
                    <label for="gudermannianBtn">Gudermannian Connection</label>
                    <button class="gudermannian-btn" id="gudermannianBtn" aria-describedby="gudermannian-desc">
                        <svg viewBox="0 0 24 24" aria-hidden="true" focusable="false"><path d="M14.59 7.41L18.17 11H6v2h12.17l-3.59 3.59L16 18l6-6-6-6-1.41 1.41zM4 6h2v12H4V6z"></path></svg>
                    </button>
                    <p id="gudermannian-desc">Animate the sec(θ) = cosh(p) connection.</p>
                </div>
            </section>

            <section class="values-section" aria-labelledby="circular-heading">
                <h2 id="circular-heading">Circular Functions</h2>
                <dl class="values-grid">
                    <div class="value-card" style="--card-color: var(--color-sin);">
                        <dt>sin(θ)</dt>
                        <dd id="val-sin">0.707</dd>
                    </div>
                    <div class="value-card" style="--card-color: var(--color-cos);">
                        <dt>cos(θ)</dt>
                        <dd id="val-cos">0.707</dd>
                    </div>
                    <div class="value-card" style="--card-color: var(--color-tan);">
                        <dt>tan(θ)</dt>
                        <dd id="val-tan">1.000</dd>
                    </div>
                    <div id="sec-card" class="value-card" style="--card-color: var(--color-sec);">
                        <dt>sec(θ)</dt>
                        <dd id="val-sec">1.414</dd>
                    </div>
                    <div class="value-card" style="--card-color: var(--color-csc);">
                        <dt>csc(θ)</dt>
                        <dd id="val-csc">1.414</dd>
                    </div>
                    <div class="value-card" style="--card-color: var(--color-cot);">
                        <dt>cot(θ)</dt>
                        <dd id="val-cot">1.000</dd>
                    </div>
                </dl>
            </section>

            <section id="hyperbolic-section" class="values-section" aria-labelledby="hyperbolic-heading">
                <h2 id="hyperbolic-heading">Hyperbolic Functions</h2>
                <p class="visually-hidden">Parameter p is calculated as the inverse Gudermannian function of theta, p = ln(sec(θ) + tan(θ)). Hyperbolic values are shown only when sec(θ) ≥ 1.</p>
                <dl class="values-grid">
                    <div class="value-card">
                        <dt>p</dt>
                        <dd id="val-p">0.881</dd>
                    </div>
                    <div class="value-card" style="--card-color: var(--color-sin);">
                        <dt>sinh(p)</dt>
                        <dd id="val-sinh">1.000</dd>
                    </div>
                    <div id="cosh-card" class="value-card" style="--card-color: var(--color-cos);">
                        <dt>cosh(p)</dt>
                        <dd id="val-cosh">1.414</dd>
                    </div>
                    <div class="value-card" style="--card-color: var(--color-tan);">
                        <dt>tanh(p)</dt>
                        <dd id="val-tanh">0.707</dd>
                    </div>
                </dl>
            </section>
            <div id="sr-announcer" class="visually-hidden" aria-live="polite" aria-atomic="true"></div>
        </aside>
    </main>

    <footer>
        <p>Interactive Trigonometry Visualization &copy; 2024. All rights reserved.</p>
    </footer>

    <script>
        class TrigVisualizer {
            constructor() {
                this.canvas = document.getElementById('mainCanvas');
                if (!this.canvas) {
                    console.error("FATAL: Canvas element not found!");
                    return;
                }
                this.ctx = this.canvas.getContext('2d');

                this.dom = {
                    slider: document.getElementById('angleSlider'),
                    speedSlider: document.getElementById('speedSlider'),
                    playPauseBtn: document.getElementById('playPauseBtn'),
                    gudermannianBtn: document.getElementById('gudermannianBtn'),
                    degOut: document.getElementById('angleDeg'),
                    radOut: document.getElementById('angleRad'),
                    speedOut: document.getElementById('speedOutput'),
                    sin: document.getElementById('val-sin'), cos: document.getElementById('val-cos'),
                    tan: document.getElementById('val-tan'), sec: document.getElementById('val-sec'),
                    csc: document.getElementById('val-csc'), cot: document.getElementById('val-cot'),
                    p: document.getElementById('val-p'), sinh: document.getElementById('val-sinh'),
                    cosh: document.getElementById('val-cosh'), tanh: document.getElementById('val-tanh'),
                    sr: document.getElementById('sr-announcer'),
                    hyperbolicSection: document.getElementById('hyperbolic-section'),
                    secCard: document.getElementById('sec-card'),
                    coshCard: document.getElementById('cosh-card'),
                };

                this.colors = this.getColors();

                this.state = {
                    angleRad: 0,
                    isPlaying: false,
                    isPulsing: false,
                    isConnectionValid: false,
                    isGudermannianAnimating: false,
                    gudermannianProgress: 0,
                    isDirty: true, // Flag to request a redraw
                };

                this.constants = {
                    epsilon: 1e-9,
                    maxVal: 10000,
                    gudermannianAnimSpeed: 0.015,
                };

                this.scale = 1;
                this.originX = 0;
                this.originY = 0;
                this.animationFrameId = null;
                this.pulseTime = 0;

                this.init();
            }

            getColors() {
                const style = getComputedStyle(document.documentElement);
                return {
                    bg: style.getPropertyValue('--surface-color').trim(),
                    grid: '#4a4a68',
                    gridLabel: style.getPropertyValue('--secondary-text-color').trim(),
                    circle: '#e0e0e5',
                    hyperbola: style.getPropertyValue('--color-hyperbola').trim(),
                    cos: style.getPropertyValue('--color-cos').trim(),
                    sin: style.getPropertyValue('--color-sin').trim(),
                    tan: style.getPropertyValue('--color-tan').trim(),
                    sec: style.getPropertyValue('--color-sec').trim(),
                    csc: style.getPropertyValue('--color-csc').trim(),
                    cot: style.getPropertyValue('--color-cot').trim(),
                    connectionGlow: style.getPropertyValue('--color-connection-glow').trim(),
                    hyperbolicArea: style.getPropertyValue('--color-hyperbolic-area').trim(),
                    text: style.getPropertyValue('--primary-text-color').trim(),
                    fontFamily: style.getPropertyValue('--font-family-sans').trim(),
                };
            }

            init() {
                this.setupCanvas();
                this.attachEventListeners();
                this.setAngle(parseFloat(this.dom.slider.value));
                this.updateSpeed();
                this.animationLoop();
            }

            attachEventListeners() {
                window.addEventListener('resize', () => this.setupCanvas());
                this.dom.slider.addEventListener('input', (e) => this.setAngle(parseFloat(e.target.value)));
                this.dom.speedSlider.addEventListener('input', () => this.updateSpeed());
                this.dom.playPauseBtn.addEventListener('click', () => this.togglePlay());
                this.dom.gudermannianBtn.addEventListener('click', () => this.startGudermannianAnimation());

                let isDragging = false;
                const handleInteraction = (e) => {
                    if (this.state.isGudermannianAnimating) return;
                    e.preventDefault();
                    const touch = e.touches ? e.touches[0] : e;
                    const rect = this.canvas.getBoundingClientRect();
                    const x = (touch.clientX - rect.left) - this.originX;
                    const y = this.originY - (touch.clientY - rect.top);
                    let angle = Math.atan2(y, x);
                    if (angle < 0) angle += 2 * Math.PI;
                    this.setAngle(angle * 180 / Math.PI);
                };

                this.canvas.addEventListener('mousedown', (e) => { isDragging = true; handleInteraction(e); });
                this.canvas.addEventListener('mousemove', (e) => { if (isDragging) handleInteraction(e); });
                document.addEventListener('mouseup', () => { isDragging = false; });
                this.canvas.addEventListener('mouseleave', () => { isDragging = false; });

                this.canvas.addEventListener('touchstart', (e) => { isDragging = true; handleInteraction(e); }, { passive: false });
                this.canvas.addEventListener('touchmove', (e) => { if (isDragging) handleInteraction(e); }, { passive: false });
                this.canvas.addEventListener('touchend', () => { isDragging = false; });
                this.canvas.addEventListener('touchcancel', () => { isDragging = false; });

                this.canvas.addEventListener('keydown', (e) => this.handleKeyDown(e));
            }

            handleKeyDown(e) {
                if (this.state.isGudermannianAnimating) return;
                let change = 0;
                if (e.key === 'ArrowRight') change = e.shiftKey ? 5 : 1;
                if (e.key === 'ArrowLeft') change = e.shiftKey ? -5 : -1;

                if (change !== 0) {
                    e.preventDefault();
                    const currentDeg = parseFloat(this.dom.slider.value);
                    let newDeg = (currentDeg + change) % 360;
                    if (newDeg < 0) newDeg += 360;
                    this.setAngle(newDeg);
                }
            }

            setupCanvas() {
                const dpr = window.devicePixelRatio || 1;
                const rect = this.canvas.parentElement.getBoundingClientRect();
                this.canvas.width = rect.width * dpr;
                this.canvas.height = rect.height * dpr;
                this.ctx.scale(dpr, dpr);

                const size = Math.min(rect.width, rect.height);
                this.scale = size / 5.5;
                this.originX = rect.width / 2;
                this.originY = rect.height / 2;
                this.requestDraw();
            }

            setAngle(deg) {
                if (this.state.isGudermannianAnimating) return;
                this.dom.slider.value = deg;
                this.state.angleRad = deg * Math.PI / 180;
                this.state.isPulsing = true;
                this.pulseTime = 0;
                this.updateValues();
                this.announceUpdate();
            }

            updateSpeed() {
                this.dom.speedOut.textContent = `${parseFloat(this.dom.speedSlider.value).toFixed(1)}x`;
            }

            togglePlay() {
                if (this.state.isGudermannianAnimating) return;
                this.state.isPlaying = !this.state.isPlaying;
                this.updateControlStates();
            }

            startGudermannianAnimation() {
                if (this.state.isConnectionValid && !this.state.isGudermannianAnimating) {
                    this.state.isGudermannianAnimating = true;
                    this.state.gudermannianProgress = 0;
                    if (this.state.isPlaying) this.state.isPlaying = false;
                    this.updateControlStates();
                }
            }

            animationLoop() {
                let needsDraw = false;
                if (this.state.isPlaying && !this.state.isGudermannianAnimating) {
                    const currentDeg = parseFloat(this.dom.slider.value);
                    const speed = parseFloat(this.dom.speedSlider.value);
                    const newDeg = (currentDeg + speed * 0.5) % 360;
                    this.setAngle(newDeg);
                    needsDraw = true;
                }
                if (this.state.isPulsing) {
                    this.pulseTime += 0.05;
                    if (this.pulseTime > Math.PI) {
                        this.state.isPulsing = false;
                        this.pulseTime = 0;
                    }
                    needsDraw = true;
                }
                if (this.state.isGudermannianAnimating) {
                    this.state.gudermannianProgress += this.constants.gudermannianAnimSpeed;
                    if (this.state.gudermannianProgress >= 1) {
                        this.state.isGudermannianAnimating = false;
                        this.state.gudermannianProgress = 0;
                        this.updateControlStates();
                    }
                    needsDraw = true;
                }

                if (needsDraw || this.state.isDirty) {
                    this.draw();
                    this.state.isDirty = false;
                }
                this.animationFrameId = requestAnimationFrame(() => this.animationLoop());
            }

            requestDraw() {
                this.state.isDirty = true;
            }

            updateValues() {
                const t = this.state.angleRad;
                const cos_t = Math.cos(t);
                const sin_t = Math.sin(t);

                this.values = {
                    cos_t, sin_t,
                    tan_t: Math.abs(cos_t) < this.constants.epsilon ? Infinity * Math.sign(sin_t) : sin_t / cos_t,
                    sec_t: Math.abs(cos_t) < this.constants.epsilon ? Infinity * Math.sign(cos_t) : 1 / cos_t,
                    csc_t: Math.abs(sin_t) < this.constants.epsilon ? Infinity * Math.sign(sin_t) : 1 / sin_t,
                    cot_t: Math.abs(sin_t) < this.constants.epsilon ? Infinity * Math.sign(cos_t) : cos_t / sin_t,
                };

                this.state.isConnectionValid = isFinite(this.values.sec_t) && this.values.sec_t >= 1 - this.constants.epsilon;

                if (this.state.isConnectionValid) {
                    const p = Math.asinh(this.values.tan_t);
                    this.values.p = p;
                    this.values.cosh_p = Math.cosh(p);
                    this.values.sinh_p = Math.sinh(p);
                    this.values.tanh_p = Math.tanh(p);
                } else {
                    this.values.p = NaN;
                    this.values.cosh_p = NaN;
                    this.values.sinh_p = NaN;
                    this.values.tanh_p = NaN;
                }

                this.updateUI();
                this.requestDraw();
            }

            formatVal(val) {
                if (isNaN(val)) return 'N/A';
                if (Math.abs(val) === Infinity) return '∞';
                if (Math.abs(val) > this.constants.maxVal) return val.toExponential(2);
                return val.toFixed(3);
            }

            updateUI() {
                const deg = this.state.angleRad * 180 / Math.PI;
                this.dom.degOut.textContent = `${deg.toFixed(1)}°`;
                this.dom.radOut.textContent = `${this.state.angleRad.toFixed(3)} rad`;
                this.dom.slider.setAttribute('aria-valuenow', deg.toFixed(1));
                this.dom.slider.setAttribute('aria-valuetext', `${deg.toFixed(1)} degrees`);

                this.dom.sin.textContent = this.formatVal(this.values.sin_t);
                this.dom.cos.textContent = this.formatVal(this.values.cos_t);
                this.dom.tan.textContent = this.formatVal(this.values.tan_t);
                this.dom.sec.textContent = this.formatVal(this.values.sec_t);
                this.dom.csc.textContent = this.formatVal(this.values.csc_t);
                this.dom.cot.textContent = this.formatVal(this.values.cot_t);

                this.dom.p.textContent = this.formatVal(this.values.p);
                this.dom.sinh.textContent = this.formatVal(this.values.sinh_p);
                this.dom.cosh.textContent = this.formatVal(this.values.cosh_p);
                this.dom.tanh.textContent = this.formatVal(this.values.tanh_p);

                this.updateControlStates();

                const shouldHighlight = this.state.isPulsing && this.state.isConnectionValid;
                this.dom.secCard.classList.toggle('connection-highlight', shouldHighlight);
                this.dom.coshCard.classList.toggle('connection-highlight', shouldHighlight);
            }

            updateControlStates() {
                const isAnimating = this.state.isGudermannianAnimating;
                this.dom.slider.disabled = isAnimating;
                this.dom.playPauseBtn.disabled = isAnimating;
                this.dom.gudermannianBtn.disabled = isAnimating || !this.state.isConnectionValid;
                this.dom.hyperbolicSection.setAttribute('aria-disabled', !this.state.isConnectionValid);

                this.dom.playPauseBtn.classList.toggle('playing', this.state.isPlaying);
                this.dom.playPauseBtn.setAttribute('aria-label', this.state.isPlaying ? 'Pause animation' : 'Play animation');
            }

            // --- Drawing Methods ---
            draw() {
                const rect = this.canvas.getBoundingClientRect();
                this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
                this.ctx.fillStyle = this.colors.bg;
                this.ctx.fillRect(0, 0, rect.width, rect.height);

                this.drawGridAndAxes();
                this.drawShapes();
                if (this.state.isConnectionValid) {
                    this.drawHyperbolicSector();
                    this.drawHyperbolicFunctions();
                    this.drawConnectionHighlight();
                }
                this.drawCircularFunctions();
                this.drawPointsAndLabels();

                if (this.state.isGudermannianAnimating) {
                    this.drawGudermannianAnimation();
                }
            }

            drawGridAndAxes() {
                this.ctx.lineWidth = 1;
                for (let i = -2; i <= 2; i++) {
                    if (i === 0) continue;
                    this.drawLine(i, -2.5, i, 2.5, this.colors.grid, 0.5);
                    this.drawLine(-2.5, i, 2.5, i, this.colors.grid, 0.5);
                    if (i !== 0) {
                        this.drawText(i.toString(), i, -0.15, this.colors.gridLabel, 12);
                        this.drawText(i.toString(), -0.15, i, this.colors.gridLabel, 12);
                    }
                }
                this.drawLine(-2.5, 0, 2.5, 0, this.colors.grid, 1); // X-axis
                this.drawLine(0, -2.5, 0, 2.5, this.colors.grid, 1); // Y-axis
            }

            drawShapes() {
                this.ctx.beginPath();
                this.ctx.arc(this.originX, this.originY, this.scale, 0, 2 * Math.PI);
                this.ctx.strokeStyle = this.colors.circle;
                this.ctx.lineWidth = 1.5;
                this.ctx.stroke();

                this.ctx.beginPath();
                for (let y = -2.5; y <= 2.5; y += 0.01) {
                    let x = Math.sqrt(1 + y * y);
                    if (y === -2.5) this.ctx.moveTo(this.originX + x * this.scale, this.originY - y * this.scale);
                    else this.ctx.lineTo(this.originX + x * this.scale, this.originY - y * this.scale);
                }
                this.ctx.strokeStyle = this.colors.hyperbola;
                this.ctx.stroke();
            }

            drawCircularFunctions() {
                const { cos_t, sin_t, tan_t, sec_t, csc_t, cot_t } = this.values;

                this.drawLine(0, 0, cos_t, sin_t, this.colors.circle, 2); // Radius

                this.drawLine(cos_t, 0, cos_t, sin_t, this.colors.sin, 4);
                this.drawLabel('sin(θ)', cos_t, 0, cos_t, sin_t);

                this.drawLine(0, 0, cos_t, 0, this.colors.cos, 4);
                this.drawLabel('cos(θ)', 0, 0, cos_t, 0);

                if (isFinite(tan_t)) {
                    this.drawLine(1, 0, 1, tan_t, this.colors.tan, 4);
                    this.drawLabel('tan(θ)', 1, 0, 1, tan_t);
                }
                if (isFinite(cot_t)) {
                    this.drawLine(0, 1, cot_t, 1, this.colors.cot, 4);
                    this.drawLabel('cot(θ)', 0, 1, cot_t, 1);
                }

                if (isFinite(sec_t) && isFinite(csc_t)) {
                    this.drawLine(sec_t, 0, 0, csc_t, this.colors.grid, 1);
                }

                if (isFinite(sec_t)) {
                    this.drawLine(0, 0, sec_t, 0, this.colors.sec, 4, [5, 5]);
                    this.drawLabel('sec(θ)', 0, 0, sec_t, 0);
                }
                if (isFinite(csc_t)) {
                    this.drawLine(0, 0, 0, csc_t, this.colors.csc, 4, [5, 5]);
                    this.drawLabel('csc(θ)', 0, 0, 0, csc_t);
                }
            }

            drawHyperbolicFunctions() {
                const { cosh_p, sinh_p, tanh_p } = this.values;
                this.drawLine(0, 0, cosh_p, sinh_p, this.colors.hyperbola, 2);

                this.drawLine(cosh_p, 0, cosh_p, sinh_p, this.colors.sin, 4, [3, 3]);
                this.drawLabel('sinh(p)', cosh_p, 0, cosh_p, sinh_p);

                this.drawLine(0, 0, cosh_p, 0, this.colors.cos, 4, [3, 3]);
                this.drawLabel('cosh(p)', 0, 0, cosh_p, 0);

                this.drawLine(1, 0, 1, tanh_p, this.colors.tan, 4, [3, 3]);
                this.drawLabel('tanh(p)', 1, 0, 1, tanh_p);
            }

            drawHyperbolicSector() {
                const { p } = this.values;
                if (Math.abs(p) < 0.01) return;

                this.ctx.beginPath();
                this.ctx.moveTo(this.originX, this.originY);
                this.ctx.lineTo(this.originX + 1 * this.scale, this.originY);

                const steps = 50;
                for (let i = 1; i <= steps; i++) {
                    const u = (i / steps) * p;
                    const x = Math.cosh(u);
                    const y = Math.sinh(u);
                    this.ctx.lineTo(this.originX + x * this.scale, this.originY - y * this.scale);
                }
                this.ctx.closePath();
                this.ctx.fillStyle = this.colors.hyperbolicArea;
                this.ctx.fill();

                const label_u = p / 2;
                const label_x = Math.cosh(label_u) * 0.8;
                const label_y = Math.sinh(label_u) * 0.8;
                this.drawText("p/2", label_x, label_y, this.colors.hyperbola, 14);
            }

            drawConnectionHighlight() {
                if (!this.state.isPulsing || this.state.isGudermannianAnimating) return;
                const { sec_t, cosh_p } = this.values;

                const pulse = (Math.sin(this.pulseTime) + 1) / 2;
                this.ctx.save();
                this.ctx.shadowBlur = pulse * 25;
                this.ctx.shadowColor = this.colors.connectionGlow;

                this.drawLine(0, 0, sec_t, 0, this.colors.sec, 5);
                this.drawLine(0, 0, cosh_p, 0, this.colors.sec, 5);

                this.ctx.restore();
            }

            drawGudermannianAnimation() {
                const { sec_t, sinh_p } = this.values;
                const progress = this.state.gudermannianProgress;
                const easeInOut = 0.5 - 0.5 * Math.cos(progress * Math.PI);

                this.ctx.save();
                this.ctx.shadowBlur = 25;
                this.ctx.shadowColor = this.colors.connectionGlow;

                const secProgress = Math.min(1, progress * 2);
                const secEase = 0.5 - 0.5 * Math.cos(secProgress * Math.PI);
                this.drawPoint(sec_t * secEase, 0, this.colors.sec, 8);

                if (progress > 0.5) {
                    const connectProgress = (progress - 0.5) * 2;
                    const connectEase = 0.5 - 0.5 * Math.cos(connectProgress * Math.PI);
                    this.drawLine(sec_t, 0, sec_t, sinh_p, this.colors.connectionGlow, 3);
                    this.drawPoint(sec_t, sinh_p * connectEase, this.colors.sec, 8);
                }
                this.ctx.restore();

                this.ctx.fillStyle = `rgba(255, 255, 255, ${easeInOut * 2 * (1 - easeInOut)})`;
                this.ctx.font = `bold clamp(16px, 3vw, 20px) ${this.colors.fontFamily}`;
                this.ctx.textAlign = 'center';
                this.ctx.textBaseline = 'bottom';
                this.ctx.fillText(`sec(θ) = cosh(p) = ${this.formatVal(sec_t)}`, this.originX, this.originY - 2.2 * this.scale);
            }

            drawPointsAndLabels() {
                const { cos_t, sin_t, cosh_p, sinh_p } = this.values;

                this.drawPoint(cos_t, sin_t, this.colors.circle, 6);
                if (this.state.isConnectionValid) {
                    this.drawPoint(cosh_p, sinh_p, this.colors.hyperbola, 6);
                }

                this.ctx.beginPath();
                this.ctx.moveTo(this.originX, this.originY);
                this.ctx.arc(this.originX, this.originY, this.scale * 0.3, 0, -this.state.angleRad, true);
                this.ctx.closePath();
                this.ctx.fillStyle = 'rgba(0, 170, 255, 0.2)';
                this.ctx.fill();
                this.drawText('θ', 0.4 * Math.cos(this.state.angleRad / 2), 0.4 * Math.sin(this.state.angleRad / 2), this.colors.text, 14);
            }

            // --- Drawing Utilities ---
            drawLine(x1, y1, x2, y2, color, width = 2, dash = []) {
                this.ctx.beginPath();
                this.ctx.moveTo(this.originX + x1 * this.scale, this.originY - y1 * this.scale);
                this.ctx.lineTo(this.originX + x2 * this.scale, this.originY - y2 * this.scale);
                this.ctx.strokeStyle = color;
                this.ctx.lineWidth = width;
                this.ctx.setLineDash(dash);
                this.ctx.stroke();
                this.ctx.setLineDash([]);
            }

            drawPoint(x, y, color, radius = 5) {
                this.ctx.beginPath();
                this.ctx.arc(this.originX + x * this.scale, this.originY - y * this.scale, radius, 0, 2 * Math.PI);
                this.ctx.fillStyle = color;
                this.ctx.fill();
            }

            drawText(text, x, y, color, size = 14) {
                this.ctx.fillStyle = color;
                this.ctx.font = `${size}px ${this.colors.fontFamily}`;
                this.ctx.textAlign = 'center';
                this.ctx.textBaseline = 'middle';
                this.ctx.fillText(text, this.originX + x * this.scale, this.originY - y * this.scale);
            }

            drawLabel(text, x1, y1, x2, y2) {
                const midX = (x1 + x2) / 2;
                const midY = (y1 + y2) / 2;
                const angle = Math.atan2(y2 - y1, x2 - x1);

                let offset = 0.2;
                if (Math.hypot(midX, midY) < 0.5) offset = 0.3; // Push labels out from center

                let offsetX = -Math.sin(angle) * offset;
                let offsetY = Math.cos(angle) * offset;

                if (Math.abs(angle) > Math.PI / 2) {
                    offsetX *= -1;
                    offsetY *= -1;
                }

                this.ctx.save();
                this.ctx.fillStyle = this.colors.text;
                this.ctx.font = `13px ${this.colors.fontFamily}`;
                this.ctx.textAlign = 'center';
                this.ctx.textBaseline = 'middle';
                this.ctx.fillText(text, this.originX + (midX + offsetX) * this.scale, this.originY - (midY + offsetY) * this.scale);
                this.ctx.restore();
            }

            announceUpdate() {
                clearTimeout(this.debounceTimer);
                this.debounceTimer = setTimeout(() => {
                    const deg = (this.state.angleRad * 180 / Math.PI).toFixed(1);
                    let announcement = `Angle set to ${deg} degrees.`;
                    if (this.state.isConnectionValid) {
                        const sec = this.dom.sec.textContent;
                        announcement += ` Secant theta and cosh p are ${sec}.`;
                    } else {
                        announcement += ` Hyperbolic connection is invalid.`;
                    }
                    this.dom.sr.textContent = announcement;
                }, 500);
            }
        }

