                Interactive canvas displaying the unit circle and unit hyperbola. Control the angle theta (θ) by dragging on the canvas, using the slider, or using arrow keys. Lines representing trigonometric functions can be toggled. When secant(θ) is valid, corresponding hyperbolic lines are drawn, highlighting the Gudermannian connection where sec(θ) = cosh(p).
            </p>
        </figure>

        <aside class="controls-panel" aria-labelledby="controls-panel-heading">
            <h2 id="controls-panel-heading" class="visually-hidden">Controls and Values Panel</h2>
            <section class="control-section" aria-labelledby="controls-heading">
                <h2 id="controls-heading">Controls</h2>
                <div class="slider-group">
                    <label for="angleSlider">Angle (θ)</label>
                    <div class="animation-controls">
                        <button class="play-pause-btn" id="playPauseBtn" aria-label="Play animation">
                            <svg class="icon-play" viewBox="0 0 24 24" aria-hidden="true" focusable="false"><path d="M8 5v14l11-7z"></path></svg>
                            <svg class="icon-pause" viewBox="0 0 24 24" aria-hidden="true" focusable="false"><path d="M6 19h4V5H6v14zm8-14v14h4V5h-4z"></path></svg>
                        </button>
                        <input type="range" id="angleSlider" min="0" max="360" value="45" step="0.1" aria-valuemin="0" aria-valuemax="360" aria-valuenow="45" aria-valuetext="45.0 degrees">
                    </div>
                    <div class="slider-output">
                        <output id="angleDeg" for="angleSlider">45.0°</output>
                        <output id="angleRad" for="angleSlider">0.785 rad</output>
                    </div>
                </div>
                <div class="slider-group">
                    <label for="speedSlider">Animation Speed</label>
                    <input type="range" id="speedSlider" min="0.1" max="2" value="0.5" step="0.1" aria-label="Animation Speed">
                    <div class="slider-output">
                        <output id="speedOutput" for="speedSlider">0.5x</output>
                    </div>
                </div>
                <div class="slider-group">
                    <label for="gudermannianSlider">Gudermannian Connection: sec(θ) = cosh(p)</label>
                    <div class="animation-controls">
                        <button class="play-pause-btn" id="gudermannianPlayBtn" aria-label="Play Gudermannian animation">
                            <svg class="icon-play" viewBox="0 0 24 24" aria-hidden="true" focusable="false"><path d="M8 5v14l11-7z"></path></svg>
                            <svg class="icon-pause" viewBox="0 0 24 24" aria-hidden="true" focusable="false"><path d="M6 19h4V5H6v14zm8-14v14h4V5h-4z"></path></svg>
                        </button>
                        <input type="range" id="gudermannianSlider" min="0" max="1" value="0" step="0.001" aria-label="Gudermannian animation progress">
                    </div>
                </div>
            </section>

            <section class="display-section" aria-labelledby="display-heading">
                <h2 id="display-heading">Display Options</h2>
                <fieldset>
                    <legend class="visually-hidden">Toggle visibility of trigonometric functions</legend>
                    <div id="visibilityToggles" class="toggle-grid"></div>
                </fieldset>
            </section>

            <section class="values-section" aria-labelledby="circular-heading">
                <h2 id="circular-heading">Circular Functions</h2>
                <dl class="values-grid">
                    <div class="value-card" data-function="sin" style="--card-color: var(--color-sin);"><dt>sin(θ)</dt><dd id="val-sin">0.707</dd></div>
                    <div class="value-card" data-function="cos" style="--card-color: var(--color-cos);"><dt>cos(θ)</dt><dd id="val-cos">0.707</dd></div>
                    <div class="value-card" data-function="tan" style="--card-color: var(--color-tan);"><dt>tan(θ)</dt><dd id="val-tan">1.000</dd></div>
                    <div id="sec-card" class="value-card" data-function="sec" style="--card-color: var(--color-sec);"><dt>sec(θ)</dt><dd id="val-sec">1.414</dd></div>
                    <div class="value-card" data-function="csc" style="--card-color: var(--color-csc);"><dt>csc(θ)</dt><dd id="val-csc">1.414</dd></div>
                    <div class="value-card" data-function="cot" style="--card-color: var(--color-cot);"><dt>cot(θ)</dt><dd id="val-cot">1.000</dd></div>
                </dl>
            </section>

            <section id="hyperbolic-section" class="values-section" aria-labelledby="hyperbolic-heading">
                <h2 id="hyperbolic-heading">Hyperbolic Functions</h2>
                <p class="visually-hidden">Parameter p is calculated as p = ln(sec(θ) + tan(θ)). Hyperbolic values are shown only when sec(θ) ≥ 1.</p>
                <dl class="values-grid">
                    <div class="value-card" data-function="p" style="--card-color: var(--color-hyperbola);"><dt>p (area/2)</dt><dd id="val-p">0.881</dd></div>
                    <div class="value-card" data-function="sinh" style="--card-color: var(--color-sin);"><dt>sinh(p)</dt><dd id="val-sinh">1.000</dd></div>
                    <div id="cosh-card" class="value-card" data-function="cosh" style="--card-color: var(--color-cos);"><dt>cosh(p)</dt><dd id="val-cosh">1.414</dd></div>
                    <div class="value-card" data-function="tanh" style="--card-color: var(--color-tan);"><dt>tanh(p)</dt><dd id="val-tanh">0.707</dd></div>
                </dl>
            </section>
            <div id="sr-announcer" class="visually-hidden" aria-live="polite" aria-atomic="true"></div>
        </aside>
    </main>

    <footer>
        <p>Interactive Trigonometry Visualization &copy; 2024. All rights reserved.</p>
    </footer>

    <script>
        class TrigVisualizer {
            static FUNCTION_DEFS = [
                { id: 'sin', colorVar: '--color-sin' }, { id: 'cos', colorVar: '--color-cos' },
                { id: 'tan', colorVar: '--color-tan' }, { id: 'sec', colorVar: '--color-sec' },
                { id: 'csc', colorVar: '--color-csc' }, { id: 'cot', colorVar: '--color-cot' },
                { id: 'p', colorVar: '--color-hyperbola' }, { id: 'sinh', colorVar: '--color-sin' },
                { id: 'cosh', colorVar: '--color-cos' }, { id: 'tanh', colorVar: '--color-tan' }
            ];

            constructor() {
                this.canvas = document.getElementById('mainCanvas');
                this.ctx = this.canvas ? this.canvas.getContext('2d') : null;

                this.dom = {
                    slider: document.getElementById('angleSlider'),
                    speedSlider: document.getElementById('speedSlider'),
                    playPauseBtn: document.getElementById('playPauseBtn'),
                    gudermannianSlider: document.getElementById('gudermannianSlider'),
                    gudermannianPlayBtn: document.getElementById('gudermannianPlayBtn'),
                    degOut: document.getElementById('angleDeg'),
                    radOut: document.getElementById('angleRad'),
                    speedOut: document.getElementById('speedOutput'),
                    sr: document.getElementById('sr-announcer'),
                    hyperbolicSection: document.getElementById('hyperbolic-section'),
                    secCard: document.getElementById('sec-card'),
                    coshCard: document.getElementById('cosh-card'),
                    visibilityToggles: document.getElementById('visibilityToggles'),
                    valueCards: document.querySelectorAll('.value-card'),
                };

                if (!this.ctx || Object.values(this.dom).some(el => !el)) {
                    console.error("FATAL: A required DOM element for the visualizer is missing.");
                    return;
                }

                this.colors = this.getColorsFromCSS();

                this.state = {
                    angleRad: 0,
                    isPlaying: false,
                    isPulsing: false,
                    isConnectionValid: false,
                    isGudermannianPlaying: false,
                    gudermannianProgress: 0,
                    highlightedFunc: null,
                    isDirty: true,
                    visibility: Object.fromEntries(TrigVisualizer.FUNCTION_DEFS.map(f => [f.id, true])),
                };

                this.constants = {
                    epsilon: 1e-9,
                    maxVal: 10000,
                    gudermannianAnimSpeed: 0.5, // seconds for full animation
                    highlightThreshold: 10, // pixels for canvas hover
                };

                this.scale = 1;
                this.originX = 0;
                this.originY = 0;
                this.animationFrameId = null;
                this.lastFrameTime = performance.now();
                this.pulseTime = 0;

                this.init();
            }

            getColorsFromCSS() {
                const style = getComputedStyle(document.documentElement);
                const colorNames = ['bg', 'grid', 'grid-label', 'circle', 'hyperbola', 'cos', 'sin', 'tan', 'sec', 'csc', 'cot', 'connection-glow', 'hyperbolic-area', 'text'];
                const colors = {};
                for (const name of colorNames) {
                    const propName = name.replace(/-([a-z])/g, g => g[1].toUpperCase());
                    colors[propName] = style.getPropertyValue(`--color-${name}`).trim();
                }
                colors.fontFamily = style.getPropertyValue('--font-sans').trim();
                return colors;
            }

            init() {
                this.setupCanvas();
                this.createVisibilityToggles();
                this.attachEventListeners();
                this.setAngle(parseFloat(this.dom.slider.value));
                this.updateSpeed();
                this.animationLoop();
            }

            createVisibilityToggles() {
                const fragment = document.createDocumentFragment();
                TrigVisualizer.FUNCTION_DEFS.forEach(({ id, colorVar }) => {
                    const label = document.createElement('label');
                    label.className = 'toggle-switch';
                    label.style.setProperty('--toggle-color', `var(${colorVar})`);

                    const input = document.createElement('input');
                    input.type = 'checkbox';
                    input.id = `toggle-${id}`;
                    input.dataset.function = id;
                    input.checked = this.state.visibility[id];

                    const slider = document.createElement('div');
                    slider.className = 'toggle-slider';

                    const text = document.createElement('span');
                    text.textContent = id;

                    label.append(input, slider, text);
                    fragment.appendChild(label);
                });
                this.dom.visibilityToggles.appendChild(fragment);
            }

            attachEventListeners() {
                window.addEventListener('resize', () => this.setupCanvas());
                this.dom.slider.addEventListener('input', (e) => this.setAngle(parseFloat(e.target.value)));
                this.dom.speedSlider.addEventListener('input', () => this.updateSpeed());
                this.dom.playPauseBtn.addEventListener('click', () => this.togglePlay());

                this.dom.gudermannianSlider.addEventListener('input', (e) => this.setGudermannianProgress(parseFloat(e.target.value)));
                this.dom.gudermannianPlayBtn.addEventListener('click', () => this.toggleGudermannianPlay());

                this.dom.visibilityToggles.addEventListener('change', (e) => {
                    if (e.target.type === 'checkbox') {
                        this.state.visibility[e.target.dataset.function] = e.target.checked;
                        this.requestDraw();
                    }
                });

                this.dom.valueCards.forEach(card => {
                    card.addEventListener('mouseenter', () => this.setHighlight(card.dataset.function));
                    card.addEventListener('mouseleave', () => this.setHighlight(null));
                    card.addEventListener('focusin', () => this.setHighlight(card.dataset.function));
                    card.addEventListener('focusout', () => this.setHighlight(null));
                });

                let isDragging = false;
                const handleInteraction = (e) => {
                    if (this.isAnyAnimationActive()) return;
                    e.preventDefault();
                    const touch = e.touches ? e.touches[0] : e;
                    const rect = this.canvas.getBoundingClientRect();
                    const x = (touch.clientX - rect.left) - this.originX;
                    const y = this.originY - (touch.clientY - rect.top);
                    let angle = Math.atan2(y, x);
                    if (angle < 0) angle += 2 * Math.PI;
                    this.setAngle(angle * 180 / Math.PI);
                };

                this.canvas.addEventListener('mousedown', (e) => { isDragging = true; handleInteraction(e); });
                this.canvas.addEventListener('mousemove', (e) => { 
                    if (isDragging) {
                        handleInteraction(e);
                    } else {
                        this.handleCanvasHover(e);
                    }
                });
                document.addEventListener('mouseup', () => { isDragging = false; });
                this.canvas.addEventListener('mouseleave', () => { 
                    isDragging = false;
                    this.setHighlight(null);
                });

                this.canvas.addEventListener('touchstart', (e) => { isDragging = true; handleInteraction(e); }, { passive: false });
                this.canvas.addEventListener('touchmove', (e) => { if (isDragging) handleInteraction(e); }, { passive: false });
                this.canvas.addEventListener('touchend', () => { isDragging = false; });
                this.canvas.addEventListener('touchcancel', () => { isDragging = false; });

                this.canvas.addEventListener('keydown', (e) => this.handleKeyDown(e));
            }

            handleKeyDown(e) {
                if (this.isAnyAnimationActive()) return;
                let change = 0;
                if (e.key === 'ArrowRight') change = e.shiftKey ? 5 : 1;
                if (e.key === 'ArrowLeft') change = e.shiftKey ? -5 : -1;

                if (change !== 0) {
                    e.preventDefault();
                    const currentDeg = parseFloat(this.dom.slider.value);
                    let newDeg = (currentDeg + change);
                    if (newDeg > 360) newDeg -= 360;
                    if (newDeg < 0) newDeg += 360;
                    this.setAngle(newDeg);
                }
            }

            setupCanvas() {
                const dpr = window.devicePixelRatio || 1;
                const rect = this.canvas.parentElement.getBoundingClientRect();
                this.canvas.width = rect.width * dpr;
                this.canvas.height = rect.height * dpr;
                this.ctx.scale(dpr, dpr);

                const size = Math.min(rect.width, rect.height);
                this.scale = size / 5.5;
                this.originX = rect.width / 2;
                this.originY = rect.height / 2;
                this.requestDraw();
            }

            setAngle(deg) {
                if (this.isAnyAnimationActive()) return;
                this.dom.slider.value = deg;
                this.state.angleRad = deg * Math.PI / 180;
                this.state.isPulsing = true;
                this.pulseTime = 0;
                this.updateValues();
                this.announceUpdate();
            }

            updateSpeed() {
                this.dom.speedOut.textContent = `${parseFloat(this.dom.speedSlider.value).toFixed(1)}x`;
            }

            togglePlay() {
                if (this.isAnyAnimationActive() && !this.state.isPlaying) return;
                this.state.isPlaying = !this.state.isPlaying;
                if (this.state.isPlaying) {
                    this.state.isGudermannianPlaying = false;
                }
                this.updateControlStates();
            }

            toggleGudermannianPlay() {
                if (!this.state.isConnectionValid) return;
                if (this.isAnyAnimationActive() && !this.state.isGudermannianPlaying) return;
                this.state.isGudermannianPlaying = !this.state.isGudermannianPlaying;
                if (this.state.isGudermannianPlaying) {
                    this.state.isPlaying = false;
                    if (this.state.gudermannianProgress >= 1) {
                        this.setGudermannianProgress(0);
                    }
                }
                this.updateControlStates();
            }

            setGudermannianProgress(progress) {
                this.state.gudermannianProgress = Math.max(0, Math.min(1, progress));
                this.dom.gudermannianSlider.value = this.state.gudermannianProgress;
                this.requestDraw();
            }

            isAnyAnimationActive() {
                return this.state.isPlaying || this.state.isGudermannianPlaying;
            }

            animationLoop(now) {
                const delta = (now - this.lastFrameTime) / 1000;
                this.lastFrameTime = now;
                let needsDraw = false;

                if (this.state.isPlaying) {
                    const currentDeg = parseFloat(this.dom.slider.value);
                    const speed = parseFloat(this.dom.speedSlider.value);
                    const newDeg = (currentDeg + speed * 30 * delta) % 360;
                    this.setAngle(newDeg);
                    needsDraw = true;
                }
                if (this.state.isGudermannianPlaying) {
                    let newProgress = this.state.gudermannianProgress + delta / this.constants.gudermannianAnimSpeed;
                    if (newProgress >= 1) {
                        newProgress = 1;
                        this.state.isGudermannianPlaying = false;
                        this.updateControlStates();
                    }
                    this.setGudermannianProgress(newProgress);
                    needsDraw = true;
                }
                if (this.state.isPulsing) {
                    this.pulseTime += delta * 4;
                    if (this.pulseTime > Math.PI) {
                        this.state.isPulsing = false;
                        this.pulseTime = 0;
                    }
                    needsDraw = true;
                }

                if (needsDraw || this.state.isDirty) {
                    this.draw();
                    this.state.isDirty = false;
                }
                this.animationFrameId = requestAnimationFrame((t) => this.animationLoop(t));
            }

            requestDraw() { this.state.isDirty = true; }

            updateValues() {
                const t = this.state.angleRad;
                const cos_t = Math.cos(t);
                const sin_t = Math.sin(t);

                this.values = {
                    cos_t, sin_t,
                    tan_t: Math.abs(cos_t) < this.constants.epsilon ? Infinity * Math.sign(sin_t) : sin_t / cos_t,
                    sec_t: Math.abs(cos_t) < this.constants.epsilon ? Infinity * Math.sign(cos_t) : 1 / cos_t,
                    csc_t: Math.abs(sin_t) < this.constants.epsilon ? Infinity * Math.sign(sin_t) : 1 / sin_t,
                    cot_t: Math.abs(sin_t) < this.constants.epsilon ? Infinity * Math.sign(cos_t) : cos_t / sin_t,
                };

                const wasConnectionValid = this.state.isConnectionValid;
                this.state.isConnectionValid = isFinite(this.values.sec_t) && this.values.sec_t >= 1 - this.constants.epsilon;

                if (!wasConnectionValid && this.state.isConnectionValid) {
                    this.setGudermannianProgress(0);
                }

                if (this.state.isConnectionValid) {
                    const p = Math.asinh(this.values.tan_t);
                    this.values.p = p;
                    this.values.cosh_p = Math.cosh(p);
                    this.values.sinh_p = Math.sinh(p);
                    this.values.tanh_p = Math.tanh(p);
                } else {
                    this.values.p = NaN; this.values.cosh_p = NaN;
                    this.values.sinh_p = NaN; this.values.tanh_p = NaN;
                }

                this.updateUI();
                this.requestDraw();
            }

            formatVal(val) {
                if (isNaN(val)) return 'N/A';
                if (Math.abs(val) === Infinity) return '∞';
                if (Math.abs(val) > this.constants.maxVal) return val.toExponential(2);
                return val.toFixed(3);
            }

            updateUI() {
                const deg = this.state.angleRad * 180 / Math.PI;
                this.dom.degOut.textContent = `${deg.toFixed(1)}°`;
                this.dom.radOut.textContent = `${this.state.angleRad.toFixed(3)} rad`;
                this.dom.slider.setAttribute('aria-valuenow', deg.toFixed(1));
                this.dom.slider.setAttribute('aria-valuetext', `${deg.toFixed(1)} degrees`);

                document.getElementById('val-sin').textContent = this.formatVal(this.values.sin_t);
                document.getElementById('val-cos').textContent = this.formatVal(this.values.cos_t);
                document.getElementById('val-tan').textContent = this.formatVal(this.values.tan_t);
                document.getElementById('val-sec').textContent = this.formatVal(this.values.sec_t);
                document.getElementById('val-csc').textContent = this.formatVal(this.values.csc_t);
                document.getElementById('val-cot').textContent = this.formatVal(this.values.cot_t);
                document.getElementById('val-p').textContent = this.formatVal(this.values.p);
                document.getElementById('val-sinh').textContent = this.formatVal(this.values.sinh_p);
                document.getElementById('val-cosh').textContent = this.formatVal(this.values.cosh_p);
                document.getElementById('val-tanh').textContent = this.formatVal(this.values.tanh_p);

                this.updateControlStates();

                const shouldHighlight = this.state.isPulsing && this.state.isConnectionValid;
                this.dom.secCard.classList.toggle('connection-highlight', shouldHighlight);
                this.dom.coshCard.classList.toggle('connection-highlight', shouldHighlight);
            }

            updateControlStates() {
                const isGudermannianMode = this.state.isGudermannianPlaying || parseFloat(this.dom.gudermannianSlider.value) > 0;
                this.dom.slider.disabled = isGudermannianMode || this.state.isPlaying;
                this.dom.playPauseBtn.disabled = isGudermannianMode;
                this.dom.gudermannianSlider.disabled = !this.state.isConnectionValid || this.state.isPlaying;
                this.dom.gudermannianPlayBtn.disabled = !this.state.isConnectionValid || this.state.isPlaying;
                this.dom.hyperbolicSection.setAttribute('aria-disabled', !this.state.isConnectionValid);

                this.dom.playPauseBtn.classList.toggle('playing', this.state.isPlaying);
                this.dom.playPauseBtn.setAttribute('aria-label', this.state.isPlaying ? 'Pause angle animation' : 'Play angle animation');
                this.dom.gudermannianPlayBtn.classList.toggle('playing', this.state.isGudermannianPlaying);
                this.dom.gudermannianPlayBtn.setAttribute('aria-label', this.state.isGudermannianPlaying ? 'Pause Gudermannian animation' : 'Play Gudermannian animation');
            }

            setHighlight(funcName) {
                if (this.state.highlightedFunc === funcName) return;
                this.state.highlightedFunc = funcName;
                this.dom.valueCards.forEach(card => {
                    card.classList.toggle('is-highlighted', card.dataset.function === funcName);
                });
                this.requestDraw();
            }

            // --- Drawing Methods ---
            draw() {
                const rect = this.canvas.getBoundingClientRect();
                this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
                this.ctx.fillStyle = this.colors.bg;
                this.ctx.fillRect(0, 0, rect.width, rect.height);

                this.drawGridAndAxes();
                this.drawShapes();
                if (this.state.isConnectionValid) {
                    if (this.state.visibility.p) this.drawHyperbolicSector();
                    this.drawHyperbolicFunctions();
                    this.drawConnectionHighlight();
                }
                this.drawCircularFunctions();
                this.drawPointsAndLabels();

                if (parseFloat(this.dom.gudermannianSlider.value) > 0 && this.state.isConnectionValid) {
                    this.drawGudermannianAnimation();
                }
            }

            drawGridAndAxes() {
                this.ctx.lineWidth = 1;
                for (let i = -2; i <= 2; i++) {
                    if (i === 0) continue;
                    this.drawLine(i, -2.5, i, 2.5, this.colors.grid, 0.5);
                    this.drawLine(-2.5, i, 2.5, i, this.colors.grid, 0.5);
                    if (i !== 0) {
                        this.drawText(i.toString(), i, -0.15, this.colors.gridLabel, 12);
                        this.drawText(i.toString(), -0.15, i, this.colors.gridLabel, 12);
                    }
                }
                this.drawLine(-2.5, 0, 2.5, 0, this.colors.grid, 1); // X-axis
                this.drawLine(0, -2.5, 0, 2.5, this.colors.grid, 1); // Y-axis
            }

            drawShapes() {
                this.ctx.beginPath();
                this.ctx.arc(this.originX, this.originY, this.scale, 0, 2 * Math.PI);
                this.ctx.strokeStyle = this.colors.circle;
                this.ctx.lineWidth = 1.5;
                this.ctx.stroke();

                this.ctx.beginPath();
                for (let y = -2.5; y <= 2.5; y += 0.01) {
                    let x = Math.sqrt(1 + y * y);
                    if (y === -2.5) this.ctx.moveTo(this.originX + x * this.scale, this.originY - y * this.scale);
                    else this.ctx.lineTo(this.originX + x * this.scale, this.originY - y * this.scale);
                }
                this.ctx.strokeStyle = this.colors.hyperbola;
                this.ctx.stroke();
            }

            drawCircularFunctions() {
                const { cos_t, sin_t, tan_t, sec_t, csc_t, cot_t } = this.values;
                const { visibility, highlightedFunc } = this.state;

                this.drawLine(0, 0, cos_t, sin_t, this.colors.circle, 2); // Radius

                if (visibility.sin) this.drawLine(cos_t, 0, cos_t, sin_t, this.colors.sin, highlightedFunc === 'sin' ? 6 : 4, [], highlightedFunc === 'sin');
                if (visibility.cos) this.drawLine(0, 0, cos_t, 0, this.colors.cos, highlightedFunc === 'cos' ? 6 : 4, [], highlightedFunc === 'cos');
                if (isFinite(tan_t) && visibility.tan) this.drawLine(1, 0, 1, tan_t, this.colors.tan, highlightedFunc === 'tan' ? 6 : 4, [], highlightedFunc === 'tan');
                if (isFinite(cot_t) && visibility.cot) this.drawLine(0, 1, cot_t, 1, this.colors.cot, highlightedFunc === 'cot' ? 6 : 4, [], highlightedFunc === 'cot');
                if (isFinite(sec_t) && visibility.sec) this.drawLine(0, 0, sec_t, 0, this.colors.sec, highlightedFunc === 'sec' ? 6 : 4, [5, 5], highlightedFunc === 'sec');
                if (isFinite(csc_t) && visibility.csc) this.drawLine(0, 0, 0, csc_t, this.colors.csc, highlightedFunc === 'csc' ? 6 : 4, [5, 5], highlightedFunc === 'csc');
            }

            drawHyperbolicFunctions() {
                const { cosh_p, sinh_p, tanh_p } = this.values;
                const { visibility, highlightedFunc } = this.state;
                this.drawLine(0, 0, cosh_p, sinh_p, this.colors.hyperbola, 2);

                if (visibility.sinh) this.drawLine(cosh_p, 0, cosh_p, sinh_p, this.colors.sin, highlightedFunc === 'sinh' ? 6 : 4, [3, 3], highlightedFunc === 'sinh');
                if (visibility.cosh) this.drawLine(0, 0, cosh_p, 0, this.colors.cos, highlightedFunc === 'cosh' ? 6 : 4, [3, 3], highlightedFunc === 'cosh');
                if (visibility.tanh) this.drawLine(1, 0, 1, tanh_p, this.colors.tan, highlightedFunc === 'tanh' ? 6 : 4, [3, 3], highlightedFunc === 'tanh');
            }

            drawHyperbolicSector() {
                const { p } = this.values;
                if (Math.abs(p) < 0.01) return;

                this.ctx.beginPath();
                this.ctx.moveTo(this.originX, this.originY);
                this.ctx.lineTo(this.originX + 1 * this.scale, this.originY);

                const steps = 50;
                for (let i = 1; i <= steps; i++) {
                    const u = (i / steps) * p;
                    const x = Math.cosh(u);
                    const y = Math.sinh(u);
                    this.ctx.lineTo(this.originX + x * this.scale, this.originY - y * this.scale);
                }
                this.ctx.closePath();
                this.ctx.fillStyle = this.colors.hyperbolicArea;
                this.ctx.fill();

                const label_u = p / 2;
                const label_x = Math.cosh(label_u) * 0.8;
                const label_y = Math.sinh(label_u) * 0.8;
                this.drawText("p/2", label_x, label_y, this.colors.hyperbola, 14);
            }

            drawConnectionHighlight() {
                if (!this.state.isPulsing || this.isAnyAnimationActive()) return;
                const { sec_t, cosh_p } = this.values;

                const pulse = (Math.sin(this.pulseTime) + 1) / 2;
                this.ctx.save();
                this.ctx.shadowBlur = pulse * 25;
                this.ctx.shadowColor = this.colors.connectionGlow;

                this.drawLine(0, 0, sec_t, 0, this.colors.sec, 5);
                this.drawLine(0, 0, cosh_p, 0, this.colors.sec, 5);

                this.ctx.restore();
            }

            drawGudermannianAnimation() {
                const { sec_t, cosh_p } = this.values;
                const p = this.state.gudermannianProgress;
                const ease = (t) => t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2;
                const progress = ease(p);

                this.ctx.save();
                this.ctx.shadowBlur = 25;
                this.ctx.shadowColor = this.colors.connectionGlow;

                // Stage 1 (0 -> 0.4): Highlight sec(θ)
                const secHighlightProgress = Math.min(1, progress / 0.4);
                this.drawLine(0, 0, sec_t * secHighlightProgress, 0, this.colors.sec, 6);

                // Stage 2 (0.4 -> 0.8): "Copy" sec(θ) line and move it to cosh(p) position
                if (progress > 0.4) {
                    const moveProgress = Math.min(1, (progress - 0.4) / 0.4);
                    const moveEase = 0.5 - 0.5 * Math.cos(moveProgress * Math.PI);
                    const yOffset = this.values.sinh_p * moveEase;
                    this.drawLine(0, yOffset, sec_t, yOffset, this.colors.sec, 4, [3,3]);
