                this.ctx.lineWidth = width;
                this.ctx.setLineDash(dash);
                this.ctx.stroke();
                this.ctx.restore();
            }

            drawPoint(x, y, color, radius = 5) {
                this.ctx.beginPath();
                this.ctx.arc(this.originX + x * this.scale, this.originY - y * this.scale, radius, 0, 2 * Math.PI);
                this.ctx.fillStyle = color;
                this.ctx.fill();
            }

            drawText(text, x, y, color, size = 14) {
                this.ctx.fillStyle = color;
                this.ctx.font = `${size}px ${this.colors.fontFamily}`;
                this.ctx.textAlign = 'center';
                this.ctx.textBaseline = 'middle';
                this.ctx.fillText(text, this.originX + x * this.scale, this.originY - y * this.scale);
            }

            drawLabel(text, x1, y1, x2, y2) {
                const midX = (x1 + x2) / 2;
                const midY = (y1 + y2) / 2;
                const angle = Math.atan2(y2 - y1, x2 - x1);

                let offset = 0.2;
                if (Math.hypot(midX, midY) < 0.5) offset = 0.3;

                let offsetX = -Math.sin(angle) * offset;
                let offsetY = Math.cos(angle) * offset;

                this.ctx.save();
                this.ctx.fillStyle = this.colors.text;
                this.ctx.font = `13px ${this.colors.fontFamily}`;
                this.ctx.textAlign = 'center';
                this.ctx.textBaseline = 'middle';

                let labelAngle = (Math.abs(angle) > Math.PI / 2 && Math.abs(angle) < 3 * Math.PI / 2) ? angle + Math.PI : angle;
                if (Math.abs(angle) > Math.PI / 2) {
                    offsetX *= -1;
                    offsetY *= -1;
                }

                this.ctx.translate(this.originX + (midX + offsetX) * this.scale, this.originY - (midY + offsetY) * this.scale);
                this.ctx.rotate(-labelAngle);
                this.ctx.fillText(text, 0, 0);
                this.ctx.restore();
            }

            // --- Interaction and Accessibility ---
            handleCanvasHover(e) {
                const rect = this.canvas.getBoundingClientRect();
                const mouseX = e.clientX - rect.left;
                const mouseY = e.clientY - rect.top;

                const x = (mouseX - this.originX) / this.scale;
                const y = (this.originY - mouseY) / this.scale;

