            getClosestFunctionToPoint(px, py) {
                const lines = [];
                const { cos_t, sin_t, tan_t, sec_t, csc_t, cot_t, cosh_p, sinh_p, tanh_p } = this.values;
                const { visibility } = this.state;

                if (visibility.sin) lines.push({ name: 'sin', x1: cos_t, y1: 0, x2: cos_t, y2: sin_t });
                if (visibility.cos) lines.push({ name: 'cos', x1: 0, y1: 0, x2: cos_t, y2: 0 });
                if (isFinite(tan_t) && visibility.tan) lines.push({ name: 'tan', x1: 1, y1: 0, x2: 1, y2: tan_t });
                if (isFinite(cot_t) && visibility.cot) lines.push({ name: 'cot', x1: 0, y1: 1, x2: cot_t, y2: 1 });
                if (isFinite(sec_t) && visibility.sec) lines.push({ name: 'sec', x1: 0, y1: 0, x2: sec_t, y2: 0 });
                if (isFinite(csc_t) && visibility.csc) lines.push({ name: 'csc', x1: 0, y1: 0, x2: 0, y2: csc_t });

                if (this.state.isConnectionValid) {
                    if (visibility.sinh) lines.push({ name: 'sinh', x1: cosh_p, y1: 0, x2: cosh_p, y2: sinh_p });
                    if (visibility.cosh) lines.push({ name: 'cosh', x1: 0, y1: 0, x2: cosh_p, y2: 0 });
                    if (visibility.tanh) lines.push({ name: 'tanh', x1: 1, y1: 0, x2: 1, y2: tanh_p });
                }

                let minDistSq = Infinity;
                let closestFunc = null;

                for (const line of lines) {
                    const dx = line.x2 - line.x1;
                    const dy = line.y2 - line.y1;
                    const lenSq = dx * dx + dy * dy;
                    if (lenSq < this.constants.epsilon) continue;

                    let t = ((px - line.x1) * dx + (py - line.y1) * dy) / lenSq;
                    t = Math.max(0, Math.min(1, t));

                    const closestX = line.x1 + t * dx;
                    const closestY = line.y1 + t * dy;
                    const distSq = (px - closestX) * (px - closestX) + (py - closestY) * (py - closestY);

                    if (distSq < minDistSq) {
                        minDistSq = distSq;
                        closestFunc = line;
                    }
                }

                return (minDistSq * this.scale * this.scale < this.constants.highlightThreshold * this.constants.highlightThreshold) ? closestFunc : null;
            }

