                hyperbolicGroups: document.querySelectorAll('.hyperbolic-group'),
                hyperbolaPoint: document.getElementById('hyperbola-point'),
                angleArc: document.getElementById('angle-arc'),
                lines: {
                    radius: document.getElementById('line-radius'), sin: document.getElementById('line-sin'),
                    cos: document.getElementById('line-cos'), tan: document.getElementById('line-tan'),
                    sec: document.getElementById('line-sec'), sinh: document.getElementById('line-sinh'),
                    cosh: document.getElementById('line-cosh'), tanh: document.getElementById('line-tanh'),
                },
                labels: {
                    angle: document.getElementById('label-angle'), sin: document.getElementById('label-sin'),
                    cos: document.getElementById('label-cos'), tan: document.getElementById('label-tan'),
                    sec: document.getElementById('label-sec'), sinh: document.getElementById('label-sinh'),
                    cosh: document.getElementById('label-cosh'), tanh: document.getElementById('label-tanh'),
                }
            };

            let isDragging = false;

            // --- INITIALIZATION ---
            function init() {
                drawStaticSVG();
                setupEventListeners();
                updateVisualization(parseFloat(slider.value));
            }

            function drawStaticSVG() {
                const gridGroup = document.getElementById('grid-group');
                gridGroup.innerHTML = '';
                for (let i = -2; i <= 2; i++) {
                    if (i === 0) continue;
                    const vLine = document.createElementNS(SVG_NS, 'line');
                    vLine.setAttribute('x1', i * SCALE); vLine.setAttribute('y1', -VIEW_BOX_LIMIT);
                    vLine.setAttribute('x2', i * SCALE); vLine.setAttribute('y2', VIEW_BOX_LIMIT);
                    vLine.setAttribute('class', 'grid-line');
                    gridGroup.appendChild(vLine);
                    const hLine = document.createElementNS(SVG_NS, 'line');
                    hLine.setAttribute('x1', -VIEW_BOX_LIMIT); hLine.setAttribute('y1', i * SCALE);
                    hLine.setAttribute('x2', VIEW_BOX_LIMIT); hLine.setAttribute('y2', i * SCALE);
                    hLine.setAttribute('class', 'grid-line');
                    gridGroup.appendChild(hLine);
                }

                // Draw mathematically correct curves
                const circlePath = Array.from({length: 101}, (_, i) => {
                    const angle = (i / 100) * 2 * Math.PI;
                    return `${i === 0 ? 'M' : 'L'} ${SCALE * Math.cos(angle)} ${-SCALE * Math.sin(angle)}`;
                }).join(' ') + ' Z';
                document.getElementById('unit-circle-path').setAttribute('d', circlePath);

                const hyperbolaPath = Array.from({length: 51}, (_, i) => {
                    const yVal = i * 0.05 * SCALE; // Generate points up to y=2.5
                    const xVal = SCALE * Math.sqrt(1 + (yVal/SCALE)**2);
                    return `${i === 0 ? 'M' : 'L'} ${xVal} ${-yVal}`;
                }).concat(Array.from({length: 50}, (_, i) => {
                    const yVal = (50 - i - 1) * 0.05 * SCALE;
                    const xVal = SCALE * Math.sqrt(1 + (yVal/SCALE)**2);
                    return `L ${xVal} ${yVal}`;
                })).join(' ');
                document.getElementById('unit-hyperbola-path-positive').setAttribute('d', hyperbolaPath);
                document.getElementById('unit-hyperbola-path-negative').setAttribute('d', hyperbolaPath);
            }

            // --- EVENT LISTENERS ---
            function setupEventListeners() {
                slider.addEventListener('input', (e) => updateVisualization(parseFloat(e.target.value)));

                const startDrag = (e) => {
                    e.preventDefault(); isDragging = true; handle.classList.add('dragging'); svg.style.cursor = 'grabbing';
                };
                const endDrag = () => {
                    isDragging = false; handle.classList.remove('dragging'); svg.style.cursor = 'default';
                };
                const drag = (e) => {
                    if (!isDragging) return;
                    e.preventDefault();
                    const CTM = svg.getScreenCTM().inverse();
                    const pt = svg.createSVGPoint();
                    const touch = e.touches ? e.touches[0] : e;
                    pt.x = touch.clientX; pt.y = touch.clientY;
                    const { x, y } = pt.matrixTransform(CTM);
                    let angleRad = Math.atan2(-y, x);
                    if (angleRad < 0) angleRad += 2 * Math.PI;
                    const angleDeg = angleRad * (180 / Math.PI);
                    slider.value = angleDeg;
                    updateVisualization(angleDeg);
                };

                handle.addEventListener('mousedown', startDrag);
                handle.addEventListener('touchstart', startDrag, { passive: false });
                window.addEventListener('mousemove', drag);
                window.addEventListener('touchmove', drag, { passive: false });
                window.addEventListener('mouseup', endDrag);
                window.addEventListener('touchend', endDrag);

                handle.addEventListener('keydown', e => {
                    let currentAngle = parseFloat(slider.value);
                    const step = e.shiftKey ? 10 : 1;
                    let handled = true;
                    switch(e.key) {
                        case 'ArrowRight': case 'ArrowUp': currentAngle += step; break;
                        case 'ArrowLeft': case 'ArrowDown': currentAngle -= step; break;
                        case 'Home': currentAngle = 0; break;
                        case 'End': currentAngle = 359.9; break;
                        default: handled = false;
                    }
                    if (handled) {
                        e.preventDefault();
                        if(currentAngle < 0) currentAngle += 360;
                        slider.value = currentAngle % 360;
                        updateVisualization(slider.value);
                    }
                });
            }

            // --- CALCULATION LOGIC ---
            function calculateValues(angleDeg) {
                const angleRad = angleDeg * (Math.PI / 180);
                const values = { angleDeg, angleRad, isHyperbolicValid: false };

                values.c = Math.cos(angleRad);
                values.s = Math.sin(angleRad);

                if (Math.abs(values.c) < ε) {
                    values.c = 0;
                    values.t = values.s > 0 ? Infinity : -Infinity;
                    values.sec = values.s > 0 ? Infinity : -Infinity;
                } else {
                    values.t = values.s / values.c;
                    values.sec = 1 / values.c;
                }

                // The hyperbolic connection p = ln(sec(θ) + tan(θ)) is only defined for real numbers
                // when sec(θ) + tan(θ) > 0, which corresponds to cos(θ) > 0.
                if (values.c > 0) {
                    values.isHyperbolicValid = true;
                    const arg = values.sec + values.t;
                    values.p = Math.log(arg);
                    values.sinh_p = Math.sinh(values.p); // which equals tan(θ)
                    values.cosh_p = Math.cosh(values.p); // which equals sec(θ)
                    values.tanh_p = Math.tanh(values.p); // which equals sin(θ)
                } else {
                    Object.assign(values, { p: NaN, sinh_p: NaN, cosh_p: NaN, tanh_p: NaN });
                }
                return values;
            }

