                const format = (val) => {
                    if (!isFinite(val)) return Number.isNaN(val) ? 'undef.' : (val > 0 ? '∞' : '-∞');
                    if (Math.abs(val) < ε) return '0.000';
                    return val.toFixed(3);
                };

                trigValuesList.innerHTML = `
                    <li><span class="name" style="color:var(--color-sin)">sin(θ)</span> <span class="value">${format(s)}</span></li>
                    <li><span class="name" style="color:var(--color-cos)">cos(θ)</span> <span class="value">${format(c)}</span></li>
                    <li><span class="name" style="color:var(--color-tan)">tan(θ)</span> <span class="value">${format(t)}</span></li>
                    <li><span class="name" style="color:var(--color-sec)">sec(θ)</span> <span class="value">${format(sec)}</span></li>`;

                hyperValuesList.innerHTML = isHyperbolicValid ? `
                    <li><span class="name">p</span> <span class="value">${format(p)}</span></li>
                    <li><span class="name" style="color:var(--color-sinh)">sinh(p)</span> <span class="value">${format(sinh_p)}</span></li>
                    <li><span class="name" style="color:var(--color-cosh)">cosh(p)</span> <span class="value">${format(cosh_p)}</span></li>
                    <li><span class="name" style="color:var(--color-tanh)">tanh(p)</span> <span class="value">${format(tanh_p)}</span></li>` 
                    : `<li>Connection invalid for cos(θ) ≤ 0</li>`;
            }

            function updateSVG(values) {
                const { angleDeg, angleRad, s, c, t, sec, cosh_p, sinh_p, tanh_p, isHyperbolicValid } = values;

                // --- Coordinates ---
                const hx = c * SCALE; // Handle x
                const hy = -s * SCALE; // Handle y (SVG y is inverted)

                const hpx = isHyperbolicValid ? cosh_p * SCALE : SCALE;
                const hpy = isHyperbolicValid ? -sinh_p * SCALE : 0;

                const tangent_x = c > 0 ? SCALE : -SCALE;
                const tan_y = c > 0 ? -t * SCALE : t * SCALE;

                // --- Points ---
                handle.setAttribute('cx', hx); handle.setAttribute('cy', hy);
                elements.hyperbolaPoint.setAttribute('cx', hpx); elements.hyperbolaPoint.setAttribute('cy', hpy);

                // --- Lines ---
                const setLine = (id, x1, y1, x2, y2) => {
                    elements.lines[id].setAttribute('x1', x1); elements.lines[id].setAttribute('y1', y1);
                    elements.lines[id].setAttribute('x2', x2); elements.lines[id].setAttribute('y2', y2);
                };
                setLine('radius', 0, 0, hx, hy);
                setLine('cos', 0, 0, hx, 0);
                setLine('sin', hx, 0, hx, hy);
                setLine('tan', tangent_x, 0, tangent_x, tan_y);
                setLine('sec', 0, 0, tangent_x, tan_y);
                setLine('cosh', 0, 0, hpx, 0);
                setLine('sinh', hpx, 0, hpx, hpy);
                setLine('tanh', tangent_x, 0, tangent_x, isHyperbolicValid ? -tanh_p * SCALE : 0);

                // --- Angle Arc & Label ---
                const arcRadius = 30;
                const endX = arcRadius * c;
                const endY = -arcRadius * s;
                const largeArcFlag = angleDeg > 180 ? 1 : 0;
                const d = `M ${arcRadius} 0 A ${arcRadius} ${arcRadius} 0 ${largeArcFlag} 1 ${endX} ${endY} L 0 0 Z`;
                elements.angleArc.setAttribute('d', d);

                // --- Labels ---
                const placeLabel = (id, x1, y1, x2, y2, text, options={}) => {
                    const el = elements.labels[id];
                    if (!el) return;
                    el.textContent = text;
                    const offset = options.offset || 12;
                    const midX = (x1 + x2) / 2;
                    const midY = (y1 + y2) / 2;
                    const angle = Math.atan2(y2 - y1, x2 - x1) + Math.PI / 2;
                    el.setAttribute('x', midX + offset * Math.cos(angle));
                    el.setAttribute('y', midY + offset * Math.sin(angle));
                };

                const angleLabelRad = angleRad / 2;
                elements.labels.angle.setAttribute('x', (arcRadius + 15) * Math.cos(angleLabelRad));
                elements.labels.angle.setAttribute('y', -(arcRadius + 15) * Math.sin(angleLabelRad));
                elements.labels.angle.textContent = 'θ';

                placeLabel('cos', 0, 0, hx, 0, 'cos', {offset: 15 * Math.sign(hy || -1)});
                placeLabel('sin', hx, 0, hx, hy, 'sin', {offset: 15 * Math.sign(hx || 1)});
                if (isFinite(t)) {
                    placeLabel('tan', tangent_x, 0, tangent_x, tan_y, 'tan', {offset: 15 * Math.sign(tangent_x)});
                    placeLabel('sec', 0, 0, tangent_x, tan_y, 'sec');
                } else {
                    elements.labels.tan.textContent = '';
                    elements.labels.sec.textContent = '';
                }

                if (isHyperbolicValid) {
                    placeLabel('cosh', 0, 0, hpx, 0, 'cosh', {offset: -15});
                    placeLabel('sinh', hpx, 0, hpx, hpy, 'sinh', {offset: 15 * Math.sign(hpx)});
                    placeLabel('tanh', tangent_x, 0, tangent_x, -tanh_p * SCALE, 'tanh', {offset: 15 * Math.sign(tangent_x)});
                }

                // --- Visibility ---
                elements.hyperbolicGroups.forEach(el => el.classList.toggle('inactive', !isHyperbolicValid));
            }

            // --- RUN ---
            init();
        });
    </script>
