                    <fieldset class="control-group">
                        <legend>Animation Controls</legend>
                        <div class="button-group">
                            <button type="button" class="button" id="play-pause-btn" aria-live="polite">Play</button>
                            <button type="button" class="button button--secondary" id="step-btn">Step</button>
                            <button type="button" class="button button--secondary" id="reset-btn">Reset</button>
                        </div>
                    </fieldset>

                    <div class="readout-panel" aria-live="polite">
                        <h3>Circular Functions</h3>
                        <table class="readout-table" aria-label="Circular function values">
