                                <tr><th scope="row"><code>cos(θ)</code>:</th><td id="val-cos">1.0000</td></tr>
                                <tr><th scope="row"><code>sin(θ)</code>:</th><td id="val-sin">0.0000</td></tr>
                                <tr><th scope="row"><code>tan(θ)</code>:</th><td id="val-tan">0.0000</td></tr>
