    </dialog>

    <script>
        document.addEventListener('DOMContentLoaded', () => {
            'use strict';

            // --- Component References ---
            const canvas = document.getElementById('trig-canvas');
            const slider = document.getElementById('angle-slider');
            const angleReadout = document.getElementById('angle-readout');
            const playPauseBtn = document.getElementById('play-pause-btn');
            const stepBtn = document.getElementById('step-btn');
            const resetBtn = document.getElementById('reset-btn');
            const animationModeGroup = document.getElementById('animation-mode-group');
            const openModalBtn = document.getElementById('open-about-btn');
            const modal = document.getElementById('about-modal');

            if (!canvas || !slider || !playPauseBtn || !modal) {
                console.error("Critical component elements not found. Aborting script.");
                return;
            }

            // --- Constants ---
            const KEY_STEP_SMALL = 1;
            const KEY_STEP_LARGE = 10;
            const KEY_STEP_PAGE = 15;
            const ANIMATION_SPEED_CONTINUOUS = 0.5;
            const ANIMATION_SPEED_GUIDED = 0.1;

            // --- Modal Logic (Production-Ready) ---
            const closeModalBtn = document.getElementById('close-modal-btn');
            const confirmModalBtn = document.getElementById('confirm-modal-btn');

            function closeDialog() {
                if (prefersReducedMotion) {
                    modal.close();
                    return;
                }
                modal.classList.add('is-closing');
                modal.addEventListener('animationend', () => {
                    modal.classList.remove('is-closing');
                    modal.close();
                }, { once: true });
            }

            openModalBtn.addEventListener('click', () => modal.showModal());
            closeModalBtn.addEventListener('click', () => closeDialog());
            confirmModalBtn.addEventListener('click', () => closeDialog());

            modal.addEventListener('click', (event) => {
                if (event.target === modal) closeDialog();
            });

            modal.addEventListener('cancel', (event) => {
                event.preventDefault();
                closeDialog();
            });

            modal.addEventListener('close', () => {
                openModalBtn.focus();
            });


            // --- Visualization Logic ---
            const ctx = canvas.getContext('2d');
            const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

            const state = {
                angleRad: 0,
                isDragging: false,
                isAnimating: false,
                animationFrameId: null,
                animationMode: 'continuous',
            };

            const style = getComputedStyle(document.documentElement);
            const colors = {
                primary: style.getPropertyValue('--vis-primary').trim(),
                secondary: style.getPropertyValue('--vis-secondary').trim(),
                tertiary: style.getPropertyValue('--vis-tertiary').trim(),
                quaternary: style.getPropertyValue('--vis-quaternary').trim(),
                hyperbola: style.getPropertyValue('--vis-hyperbola').trim(),
                link: style.getPropertyValue('--vis-link').trim(),
                axes: style.getPropertyValue('--vis-axes').trim(),
                circle: style.getPropertyValue('--vis-circle').trim(),
                text: style.getPropertyValue('--color-text').trim()
            };

            let C, R; // Canvas Center and Radius

            function setupCanvas() {
                const dpr = window.devicePixelRatio || 1;
                const rect = canvas.getBoundingClientRect();
                canvas.width = rect.width * dpr;
                canvas.height = rect.height * dpr;
                ctx.scale(dpr, dpr);
                C = { x: rect.width / 2, y: rect.height / 2 };
                R = Math.min(rect.width, rect.height) * 0.35;
                drawAll();
            }

            function drawLabel(text, x, y, color, alignment = 'center', baseline = 'middle') {
                ctx.fillStyle = color;
                ctx.textAlign = alignment;
                ctx.textBaseline = baseline;
                ctx.fillText(text, x, y);
            }

            function drawAll() {
                const rect = canvas.getBoundingClientRect();
                ctx.clearRect(0, 0, rect.width, rect.height);
                ctx.font = '14px ' + style.getPropertyValue('--font-family-sans').trim();

                // --- Calculations ---
                const cosA = Math.cos(state.angleRad);
                const sinA = Math.sin(state.angleRad);
                const isAtAsymptote = Math.abs(cosA) < 1e-9;

                const tanA = Math.tan(state.angleRad);
                const secA = 1 / cosA;

                const p = Math.asinh(tanA);
                const coshP = Math.cosh(p);
                const sinhP = Math.sinh(p);

                // --- Update Readouts ---
                document.getElementById('val-cos').textContent = cosA.toFixed(4);
                document.getElementById('val-sin').textContent = sinA.toFixed(4);
                document.getElementById('val-tan').textContent = isAtAsymptote ? (sinA >= 0 ? '+∞' : '-∞') : tanA.toFixed(4);
                document.getElementById('val-sec').textContent = isAtAsymptote ? (cosA >= 0 ? '+∞' : '-∞') : secA.toFixed(4);
                document.getElementById('val-p').textContent = isFinite(p) ? p.toFixed(4) : (p > 0 ? '+∞' : '-∞');
                document.getElementById('val-cosh').textContent = isFinite(coshP) ? coshP.toFixed(4) : '+∞';
                document.getElementById('val-sinh').textContent = isFinite(sinhP) ? sinhP.toFixed(4) : (sinhP > 0 ? '+∞' : '-∞');

                // --- Base drawing: Axes, Circle, Hyperbola ---
                ctx.strokeStyle = colors.axes;
                ctx.lineWidth = 1;
                ctx.beginPath();
                ctx.moveTo(0, C.y); ctx.lineTo(rect.width, C.y);
                ctx.moveTo(C.x, 0); ctx.lineTo(C.x, rect.height);
                ctx.stroke();

                ctx.strokeStyle = colors.hyperbola;
                ctx.lineWidth = 2;
                ctx.beginPath();
                const pMax = 3;
                for (let p_draw = -pMax; p_draw <= pMax; p_draw += 0.01) {
                    const hx_draw = C.x + Math.cosh(p_draw) * R;
                    const hy_draw = C.y - Math.sinh(p_draw) * R;
                    if (p_draw === -pMax) ctx.moveTo(hx_draw, hy_draw); else ctx.lineTo(hx_draw, hy_draw);
                }
                for (let p_draw = -pMax; p_draw <= pMax; p_draw += 0.01) {
                    const hx_draw = C.x - Math.cosh(p_draw) * R;
                    const hy_draw = C.y - Math.sinh(p_draw) * R;
                    if (p_draw === -pMax) ctx.moveTo(hx_draw, hy_draw); else ctx.lineTo(hx_draw, hy_draw);
                }
                ctx.stroke();

                ctx.strokeStyle = colors.circle;
                ctx.lineWidth = 2;
                ctx.beginPath();
                ctx.arc(C.x, C.y, R, 0, 2 * Math.PI);
                ctx.stroke();

                // --- Key Points ---
                const circlePoint = { x: C.x + cosA * R, y: C.y - sinA * R };
                const tangentIntersectPoint = { x: C.x + secA * R, y: C.y - tanA * R };
                const hyperbolaPoint = { x: C.x + coshP * R * Math.sign(cosA || 1), y: C.y - sinhP * R };

                // --- Feature 1: Visualize Trig Functions ---
                if (!isAtAsymptote) {
                    // Cosine
                    ctx.strokeStyle = colors.primary; ctx.lineWidth = 3;
                    ctx.beginPath(); ctx.moveTo(C.x, circlePoint.y); ctx.lineTo(circlePoint.x, circlePoint.y); ctx.stroke();
                    drawLabel('cos', C.x + cosA * R / 2, circlePoint.y - 10, colors.primary);

                    // Sine
                    ctx.strokeStyle = colors.secondary; ctx.lineWidth = 3;
                    ctx.beginPath(); ctx.moveTo(circlePoint.x, C.y); ctx.lineTo(circlePoint.x, circlePoint.y); ctx.stroke();
                    drawLabel('sin', circlePoint.x + 10 * Math.sign(cosA || 1), C.y - sinA * R / 2, colors.secondary, 'left');

                    // Tangent
                    ctx.strokeStyle = colors.tertiary; ctx.lineWidth = 3;
                    ctx.beginPath(); ctx.moveTo(C.x + R * Math.sign(cosA || 1), C.y); ctx.lineTo(C.x + R * Math.sign(cosA || 1), C.y - tanA * R); ctx.stroke();
                    drawLabel('tan', C.x + R * Math.sign(cosA || 1) + 10 * Math.sign(cosA || 1), C.y - tanA * R / 2, colors.tertiary, 'left');

                    // Secant
                    ctx.strokeStyle = colors.quaternary; ctx.lineWidth = 3;
                    ctx.beginPath(); ctx.moveTo(C.x, C.y); ctx.lineTo(C.x + secA * R, C.y); ctx.stroke();
                    drawLabel('sec', C.x + secA * R / 2, C.y + 15, colors.quaternary);
                }

                // Radius line
                ctx.strokeStyle = colors.circle; ctx.lineWidth = 2;
                ctx.beginPath(); ctx.moveTo(C.x, C.y); ctx.lineTo(circlePoint.x, circlePoint.y); ctx.stroke();

                // --- Feature 2: Gudermannian Connection ---
                ctx.setLineDash([4, 4]);
                ctx.strokeStyle = colors.link;
                ctx.lineWidth = (state.animationMode === 'guided' && state.isAnimating) ? 3 : 1.5;

                if (isFinite(hyperbolaPoint.x) && isFinite(hyperbolaPoint.y) && isFinite(tangentIntersectPoint.x) && isFinite(tangentIntersectPoint.y) ) {
                    ctx.beginPath();
                    ctx.moveTo(hyperbolaPoint.x, hyperbolaPoint.y);
                    ctx.lineTo(hyperbolaPoint.x, C.y);
                    ctx.stroke();

                    ctx.beginPath();
                    ctx.moveTo(hyperbolaPoint.x, hyperbolaPoint.y);
                    ctx.lineTo(tangentIntersectPoint.x, hyperbolaPoint.y);
                    ctx.stroke();
                }
                ctx.setLineDash([]);

                // Draw points on top
                ctx.fillStyle = colors.circle;
                ctx.beginPath(); ctx.arc(circlePoint.x, circlePoint.y, 5, 0, 2 * Math.PI); ctx.fill();

                if (isFinite(hyperbolaPoint.x) && isFinite(hyperbolaPoint.y)) {
                    ctx.fillStyle = colors.hyperbola;
                    ctx.beginPath(); ctx.arc(hyperbolaPoint.x, hyperbolaPoint.y, 5, 0, 2 * Math.PI); ctx.fill();
                }
            }

            function update(angleDeg) {
                let deg = parseFloat(angleDeg);
                deg = (deg % 360 + 360) % 360;

                slider.value = deg;
                state.angleRad = deg * Math.PI / 180;
                angleReadout.textContent = `${deg.toFixed(2)}°`;
                drawAll();
            }

            function handleInteraction(e) {
                const rect = canvas.getBoundingClientRect();
                const x = (e.clientX ?? e.touches[0].clientX) - rect.left;
                const y = (e.clientY ?? e.touches[0].clientY) - rect.top;
                const dx = x - C.x;
                const dy = -(y - C.y);
                const newAngleRad = Math.atan2(dy, dx);
                update(newAngleRad * 180 / Math.PI);
            }

            function animate() {
                const speed = state.animationMode === 'guided' ? ANIMATION_SPEED_GUIDED : ANIMATION_SPEED_CONTINUOUS;
                let newAngleDeg = (parseFloat(slider.value) + speed);
                update(newAngleDeg);
                state.animationFrameId = requestAnimationFrame(animate);
            }

            function toggleAnimation() {
                state.isAnimating = !state.isAnimating;
                if (state.isAnimating) {
                    playPauseBtn.textContent = 'Pause';
                    animate();
                } else {
                    cancelAnimationFrame(state.animationFrameId);
                    state.animationFrameId = null;
                    playPauseBtn.textContent = 'Play';
                    drawAll(); // Redraw once to remove any animation highlights
                }
            }

            if (prefersReducedMotion) {
                playPauseBtn.disabled = true;
                playPauseBtn.title = "Animation disabled due to system settings.";
            } else {
                 playPauseBtn.addEventListener('click', toggleAnimation);
            }

            slider.addEventListener('input', () => update(slider.value));
            resetBtn.addEventListener('click', () => update(0));
            stepBtn.addEventListener('click', () => update(parseFloat(slider.value) + 5));
            animationModeGroup.addEventListener('change', (e) => {
                state.animationMode = e.target.value;
            });

            canvas.addEventListener('mousedown', (e) => { state.isDragging = true; handleInteraction(e); canvas.focus(); });
            canvas.addEventListener('mouseup', () => { state.isDragging = false; });
            canvas.addEventListener('mouseleave', () => { state.isDragging = false; });
            canvas.addEventListener('mousemove', (e) => { if (state.isDragging) handleInteraction(e); });

            canvas.addEventListener('touchstart', (e) => { e.preventDefault(); state.isDragging = true; handleInteraction(e); }, { passive: false });
            canvas.addEventListener('touchend', (e) => { e.preventDefault(); state.isDragging = false; }, { passive: false });
            canvas.addEventListener('touchmove', (e) => { e.preventDefault(); if(state.isDragging) handleInteraction(e); }, { passive: false });

            canvas.addEventListener('keydown', (e) => {
                let currentAngleDeg = parseFloat(slider.value);
                let step = e.shiftKey ? KEY_STEP_LARGE : KEY_STEP_SMALL;
                let changed = true;

                switch(e.key) {
                    case 'ArrowLeft': case 'ArrowDown': currentAngleDeg -= step; break;
                    case 'ArrowRight': case 'ArrowUp': currentAngleDeg += step; break;
                    case 'PageUp': currentAngleDeg += KEY_STEP_PAGE; break;
                    case 'PageDown': currentAngleDeg -= KEY_STEP_PAGE; break;
                    case 'Home': currentAngleDeg = 0; break;
                    case 'End': currentAngleDeg = 359.9; break;
                    default: changed = false;
                }

                if (changed) {
                    e.preventDefault();
                    update(currentAngleDeg);
                }
            });

            // --- Initial Setup ---
            const resizeObserver = new ResizeObserver(setupCanvas);
            resizeObserver.observe(canvas);
            update(30);
        });
    </script>
</body>
